import React from 'react';
import { FormElement } from '../../types';
import { Input } from '../../../ui/wireframe-ports/Input';
import { AccordionItem } from '../../../ui/wireframe-ports/Accordion';
import { Trash2, Plus } from 'lucide-react';

interface OptionsPropertiesProps {
    element: FormElement;
    onChange: (key: keyof FormElement, value: any) => void;
    title?: string;
}

export const OptionsProperties: React.FC<OptionsPropertiesProps> = ({
    element,
    onChange,
    title = "Options"
}) => {
    const sourceType = element.dataSourceType || 'list';

    return (
        <AccordionItem title={title} defaultOpen>
            <div className="space-y-4 pt-4 px-1">
                <div className="mb-4">
                    <div className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-2">Data Source</div>
                    <div className="flex bg-slate-100 p-0.5 rounded-md border border-slate-200">
                        {[
                            { id: 'list', label: 'List' },
                            { id: 'json', label: 'JSON' },
                            { id: 'endpoint', label: 'Endpoint' }
                        ].map(source => (
                            <button
                                key={source.id}
                                onClick={() => onChange('dataSourceType', source.id)}
                                className={`flex-1 py-1.5 text-[10px] font-bold rounded transition-all ${sourceType === source.id ? 'bg-emerald-500 text-white shadow-sm' : 'text-slate-600'}`}
                            >
                                {source.label}
                            </button>
                        ))}
                    </div>
                </div>

                {sourceType === 'list' && (
                    <>
                        <div className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-2">Options</div>
                        {element.options?.map((opt, i) => (
                            <div key={i} className="relative pl-8 space-y-2 pb-4 border-b border-slate-100 last:border-0">
                                {/* Connector Arrow Index */}
                                <div className="absolute left-0 top-3 flex items-center gap-2 text-[10px] font-bold text-slate-400">
                                    <span>{i}</span>
                                    <span className="opacity-50">→</span>
                                </div>

                                <div className="flex gap-2">
                                    <input
                                        placeholder="Label"
                                        className="flex-1 bg-white border border-slate-200 rounded px-2 py-1.5 text-xs focus:ring-1 focus:ring-emerald-500 outline-none"
                                        value={opt.label}
                                        onChange={(e) => {
                                            const newOptions = [...(element.options || [])];
                                            newOptions[i] = { ...opt, label: e.target.value, value: e.target.value.toLowerCase().replace(/\s+/g, '_') };
                                            onChange('options', newOptions);
                                        }}
                                    />
                                    <button
                                        className="p-1 px-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded transition-colors"
                                        onClick={() => {
                                            const newOptions = [...(element.options || [])];
                                            newOptions.splice(i, 1);
                                            onChange('options', newOptions);
                                        }}
                                    >
                                        <Trash2 size={14} />
                                    </button>
                                </div>

                                {(element.type.includes('blocks') || element.type.includes('group') || element.type.includes('multiselect') || element.type === 'top-of-mind') && (
                                    <textarea
                                        placeholder="Description"
                                        className="w-full bg-slate-50 border border-slate-100 rounded px-2 py-1 text-[10px] text-slate-500 focus:ring-1 focus:ring-emerald-500 outline-none resize-none h-12"
                                        value={opt.description || ''}
                                        onChange={(e) => {
                                            const newOptions = [...(element.options || [])];
                                            newOptions[i] = { ...opt, description: e.target.value };
                                            onChange('options', newOptions);
                                        }}
                                    />
                                )}
                            </div>
                        ))}
                        <button
                            className="w-full py-2 bg-emerald-500 hover:bg-emerald-600 text-white rounded text-[10px] font-bold transition-all shadow-sm flex items-center justify-center gap-2 uppercase tracking-wide mt-2"
                            onClick={() => {
                                const newOptions = [...(element.options || []), { label: 'New Option', value: 'new_option' }];
                                onChange('options', newOptions);
                            }}
                        >
                            <Plus size={14} /> Add Option
                        </button>
                    </>
                )}

                {sourceType === 'json' && (
                    <div className="space-y-4">
                        <div className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-2">Static JSON</div>
                        <textarea
                            className="w-full h-40 bg-slate-900 text-emerald-400 font-mono text-[10px] p-4 rounded-xl border border-slate-800 outline-none focus:ring-1 focus:ring-emerald-500"
                            value={element.dataSourceJson || '[\n  { "label": "Option A", "value": "a" }\n]'}
                            onChange={(e) => onChange('dataSourceJson', e.target.value)}
                        />
                    </div>
                )}

                {sourceType === 'endpoint' && (
                    <div className="space-y-4">
                        <div className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-2">API Configuration</div>
                        <Input label="Endpoint URL" value={element.dataSourceUrl || ''} placeholder="https://api.example.com/data" onChange={(e) => onChange('dataSourceUrl', e.target.value)} />
                        <div className="grid grid-cols-2 gap-2">
                            <Input label="Label Key" value={element.dataSourceLabelKey || 'label'} onChange={(e) => onChange('dataSourceLabelKey', e.target.value)} />
                            <Input label="Value Key" value={element.dataSourceValueKey || 'value'} onChange={(e) => onChange('dataSourceValueKey', e.target.value)} />
                        </div>
                    </div>
                )}
            </div>
        </AccordionItem>
    );
};
