import React from 'react';
import { FormElement } from '../../types';

interface ToggleCanvasProps {
    element: FormElement;
    isSelected: boolean;
}

export const ToggleCanvas: React.FC<ToggleCanvasProps> = ({ element, isSelected }) => {
    return (
        <div className={`flex items-center gap-2 ${element.align === 'center' ? 'justify-center' : element.align === 'right' ? 'justify-end' : ''}`}>
            <div className={`w-9 h-5 rounded-full relative transition-colors ${element.selectedByDefault ? 'bg-primary' : 'bg-slate-200'}`}>
                <div className={`absolute top-0.5 h-4 w-4 bg-white rounded-full shadow-sm transition-transform ${element.selectedByDefault ? 'left-4.5 translate-x-full ml-[-2px]' : 'left-0.5'}`}></div>
            </div>
            {element.toggleText && <span className="text-sm text-slate-700">{element.toggleText}</span>}
            {element.selectedByDefault ? (element.toggleOnLabel && <span className="text-sm text-slate-700">{element.toggleOnLabel}</span>) : (element.toggleOffLabel && <span className="text-sm text-slate-700">{element.toggleOffLabel}</span>)}
        </div>
    );
};
