import React from 'react';
import { FormElement } from '../../types';

interface ContainerRendererProps {
    element: FormElement;
    renderRecursiveElement: (element: FormElement, parentIndex?: number, prefixForName?: string, parentDirection?: string) => React.ReactNode;
}

export const ContainerRenderer: React.FC<ContainerRendererProps> = ({
    element,
    renderRecursiveElement
}) => {
    // Determine layout structure
    const isFlex = element.flexDirection === 'row' || element.flexDirection === 'column';
    const displayClass = isFlex ? 'flex' : 'grid';

    // Grid Cols (only if grid)
    let gridCols = !isFlex ? "grid-cols-12" : "";
    if (!isFlex && element.type === 'two-columns') gridCols = "grid-cols-2";
    if (!isFlex && element.type === 'three-columns') gridCols = "grid-cols-3";
    if (!isFlex && element.type === 'four-columns') gridCols = "grid-cols-4";

    // Styling variants
    const styleClasses = {
        simple: "",
        card: "bg-white p-6 rounded-xl shadow-sm border border-slate-200",
        paper: "bg-[#fffdfa] p-8 shadow-md border border-slate-100"
    };
    const variantClass = styleClasses[element.containerStyle as keyof typeof styleClasses] || "";

    // Unit helpers
    const toUnit = (val: any) => {
        if (!val) return undefined;
        if (typeof val === 'string' && val.includes('-')) return undefined; // Assume it's a class
        return isNaN(Number(val)) ? val : `${val}px`;
    };

    const layoutStyles: React.CSSProperties = {
        display: displayClass as any,
        flexDirection: element.flexDirection,
        alignItems: element.alignItems || (isFlex ? 'center' : undefined),
        justifyContent: element.justifyContent,
        gap: toUnit(element.gap),
        padding: toUnit(element.padding),
        gridColumn: element.colSpan ? `span ${element.colSpan}` : undefined
    };

    return (
        <div
            key={element.id}
            className={`${displayClass} ${gridCols} ${variantClass} ${element.className || ''}`}
            style={layoutStyles}
        >
            {element.children?.map((child, idx) => renderRecursiveElement(child, idx, element.id))}
        </div>
    );
};
