import React from 'react';
import { FormElement } from '../../types';

interface PhoneCanvasProps {
    element: FormElement;
    isSelected: boolean;
}

export const PhoneCanvas: React.FC<PhoneCanvasProps> = ({ element, isSelected }) => {
    let heightClass = "h-10";
    if (element.size === 'sm') heightClass = "h-8";
    else if (element.size === 'lg') heightClass = "h-12";

    return (
        <div className={`flex w-full ${heightClass} rounded-md border bg-white overflow-hidden ${isSelected ? 'border-primary' : 'border-slate-300'} ${element.disabled ? 'opacity-60 cursor-not-allowed' : ''}`}>
            <div className="bg-slate-50 px-3 border-r border-slate-200 flex items-center text-sm text-slate-500 gap-1">
                <span>🇺🇸</span> <span>+1</span>
            </div>
            <input
                type="tel"
                placeholder={element.placeholder}
                disabled={element.disabled}
                readOnly={element.readOnly}
                defaultValue={element.defaultValue as any}
                className="flex-1 px-3 text-sm outline-none bg-transparent"
            />
        </div>
    );
};
