import React, { useState, useRef, useEffect, useMemo } from 'react';
import { ChevronDown, X, Check, Loader2, Search } from 'lucide-react';
import { SelectOption } from '@/components/form-engine/types';

export interface BaseSelectProps {
    label?: string;
    error?: string;
    description?: string;
    placeholder?: string;
    options: SelectOption[];
    value?: string | string[];
    onChange?: (value: string | string[]) => void;
    onSearchChange?: (query: string) => void;
    loading?: boolean;
    multiple?: boolean;
    disabled?: boolean;
    required?: boolean;
    canClear?: boolean;
    searchable?: boolean;
    noOptionsText?: string;
    noResultsText?: string;
    className?: string;

    // Advanced Props
    strictSearch?: boolean;
    trackBy?: string;
    allowNewOption?: boolean;
    appendNewOption?: boolean;
    addOn?: string[];
    canDeselect?: boolean;
    closeOnSelect?: boolean;
    displayCaret?: boolean;
    truncate?: boolean;
    openDirection?: 'top' | 'bottom';
    optionLimit?: number;
    inputType?: string;
    autoComplete?: string;
    minSearchLength?: number;
    size?: 'default' | 'sm' | 'md' | 'lg';
}

export const BaseSelect: React.FC<BaseSelectProps> = ({
    label,
    error,
    description,
    placeholder = "Select...",
    options = [],
    value,
    onChange,
    onSearchChange,
    loading = false,
    multiple = false,
    disabled = false,
    canClear = true,
    searchable = true,
    noOptionsText = "No options available",
    noResultsText = "No results found",
    className = "",
    size = 'md',

    // Advanced Defaults
    strictSearch = false,
    trackBy = 'label',
    allowNewOption = false,
    appendNewOption = true,
    addOn = ['Enter'],
    canDeselect = false,
    closeOnSelect, // will default based on multiple
    displayCaret = true,
    truncate = true,
    openDirection = 'bottom',
    optionLimit,
    inputType = "text",
    autoComplete = "off",
    minSearchLength = 0
}) => {
    // Determine default closeOnSelect
    const finalCloseOnSelect = closeOnSelect !== undefined ? closeOnSelect : !multiple;
    const [isOpen, setIsOpen] = useState(false);
    const [isFocused, setIsFocused] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const [activeIndex, setActiveIndex] = useState(-1);
    const containerRef = useRef<HTMLDivElement>(null);
    const searchInputRef = useRef<HTMLInputElement>(null);

    // Filtered options for local search
    const filteredOptions = useMemo(() => {
        let result = options;
        if (searchable && searchQuery) {
            const query = searchQuery.toLowerCase();
            result = options.filter(opt => {
                const valueToSearch = opt[trackBy] !== undefined ? opt[trackBy] : opt.label;
                const searchField = String(valueToSearch || '').toLowerCase();
                if (strictSearch) {
                    return searchField.startsWith(query);
                }
                return searchField.includes(query);
            });
        }

        if (optionLimit && optionLimit > 0) {
            result = result.slice(0, optionLimit);
        }

        return result;
    }, [options, searchQuery, searchable, strictSearch, trackBy, optionLimit]);

    // Reset activeIndex when searching
    useEffect(() => {
        setActiveIndex(-1);
    }, [searchQuery, filteredOptions]);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    useEffect(() => {
        if (isOpen && searchable && searchInputRef.current) {
            searchInputRef.current.focus();
        }
    }, [isOpen, searchable]);

    const handleToggle = () => {
        if (disabled) return;
        setIsOpen(!isOpen);
        if (!isOpen) setSearchQuery('');
    };

    const handleSelect = (option: SelectOption) => {
        if (multiple) {
            const currentValues = Array.isArray(value) ? value : [];
            const isSelected = currentValues.includes(option.value);

            if (isSelected && canDeselect) {
                const newValue = currentValues.filter(v => v !== option.value);
                onChange?.(newValue);
            } else if (!isSelected) {
                const newValue = [...currentValues, option.value];
                onChange?.(newValue);
            }
        } else {
            const isSelected = value === option.value;
            if (isSelected && canDeselect) {
                onChange?.('');
            } else {
                onChange?.(option.value);
            }
        }

        if (finalCloseOnSelect) {
            setIsOpen(false);
        }
        setSearchQuery('');
    };

    const handleClear = (e: React.MouseEvent) => {
        e.stopPropagation();
        onChange?.(multiple ? [] : '');
        setSearchQuery('');
    };

    const handleSearchChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const query = e.target.value;
        setSearchQuery(query);
        onSearchChange?.(query);
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (!isOpen) return;

        if (e.key === 'ArrowDown') {
            e.preventDefault();
            setActiveIndex(prev => (prev < filteredOptions.length - 1 ? prev + 1 : 0));
        } else if (e.key === 'ArrowUp') {
            e.preventDefault();
            setActiveIndex(prev => (prev > 0 ? prev - 1 : filteredOptions.length - 1));
        } else if (e.key === 'Enter') {
            e.preventDefault();
            if (activeIndex >= 0 && activeIndex < filteredOptions.length) {
                handleSelect(filteredOptions[activeIndex]);
            } else if (filteredOptions.length === 1) {
                handleSelect(filteredOptions[0]);
            } else if (allowNewOption && searchQuery) {
                handleSelect({
                    label: searchQuery,
                    value: searchQuery.toLowerCase().replace(/\s+/g, '_'),
                    description: 'Novo item'
                });
            }
            return;
        }

        if (allowNewOption && searchQuery && addOn.includes(e.key)) {
            e.preventDefault();
            const newOption: SelectOption = {
                label: searchQuery,
                value: searchQuery.toLowerCase().replace(/\s+/g, '_'),
                description: 'Novo item'
            };

            const existing = options.find(o => o.label.toLowerCase() === searchQuery.toLowerCase());
            if (existing) {
                handleSelect(existing);
            } else {
                if (appendNewOption) {
                    handleSelect(newOption);
                }
                setSearchQuery('');
            }
        }
    };

    const selectedOptions = useMemo(() => {
        if (multiple) {
            const values = Array.isArray(value) ? value : [];
            return values.map(val => {
                const existing = options.find(opt => opt.value === val);
                if (existing) return existing;
                return { label: val, value: val };
            });
        } else {
            if (!value) return [];
            const existing = options.find(opt => opt.value === value);
            if (existing) return [existing];
            return [{ label: value as string, value: value as string }];
        }
    }, [options, value, multiple]);

    const displayValue = selectedOptions.map(opt => opt.label).join(', ');

    const sizeClasses = {
        sm: 'min-h-[32px] text-xs py-1',
        md: 'min-h-[42px] text-sm py-2',
        lg: 'min-h-[52px] text-base py-3',
        default: 'min-h-[42px] text-sm py-2'
    };

    const currentSizeClass = sizeClasses[size as keyof typeof sizeClasses] || sizeClasses.md;

    return (
        <div className={`relative w-full ${className}`} ref={containerRef}>
            <div
                className={`
                    flex items-center gap-2 relative w-full rounded-lg border bg-muted/30 px-3 shadow-sm transition-all cursor-pointer
                    ${error ? 'border-red-500 ring-red-100' : (isOpen || isFocused) ? 'border-primary ring-2 ring-primary/20' : 'border-border/50 hover:border-border'}
                    ${disabled ? 'opacity-60 cursor-not-allowed bg-muted' : ''}
                    ${currentSizeClass}
                `}
                onClick={handleToggle}
                onFocus={() => setIsFocused(true)}
                onBlur={() => setIsFocused(false)}
            >
                <div className="flex flex-wrap gap-1.5 flex-1 min-w-0">
                    {selectedOptions.length === 0 && !isOpen && (
                        <span className="text-muted-foreground/40 text-sm select-none truncate">
                            {placeholder}
                        </span>
                    )}

                    {multiple ? (
                        selectedOptions.map(opt => (
                            <span
                                key={opt.value}
                                className="inline-flex items-center gap-1 rounded-md bg-emerald-50 px-2 py-0.5 text-xs font-semibold text-emerald-700 border border-emerald-100 animate-in fade-in zoom-in-95 duration-200"
                            >
                                {opt.label}
                                <button
                                    type="button"
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        handleSelect(opt);
                                    }}
                                    className="text-emerald-500 hover:text-emerald-700 transition-colors"
                                >
                                    <X size={12} />
                                </button>
                            </span>
                        ))
                    ) : (
                        !isOpen && selectedOptions.length > 0 && (
                            <span className="text-slate-900 text-sm truncate">{displayValue}</span>
                        )
                    )}

                    {isOpen && searchable && (
                        <input
                            ref={searchInputRef}
                            type={inputType}
                            autoComplete={autoComplete}
                            className="bg-transparent border-none p-0 focus:ring-0 text-sm w-full outline-none"
                            placeholder={selectedOptions.length > 0 ? '' : placeholder}
                            value={searchQuery}
                            onChange={handleSearchChange}
                            onKeyDown={handleKeyDown}
                            onClick={(e) => e.stopPropagation()}
                        />
                    )}
                </div>

                <div className="flex items-center gap-1 shrink-0 ml-auto">
                    {loading && <Loader2 size={16} className="animate-spin text-slate-400" />}

                    {canClear && (value && (Array.isArray(value) ? value.length > 0 : value !== '')) && !disabled && (
                        <button
                            type="button"
                            onClick={handleClear}
                            className="p-0.5 hover:bg-slate-100 rounded-full text-slate-400 hover:text-slate-600 transition-colors"
                        >
                            <X size={14} />
                        </button>
                    )}

                    {displayCaret && (
                        <ChevronDown
                            size={18}
                            className={`text-slate-400 transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`}
                        />
                    )}
                </div>
            </div>

            {/* Dropdown - Moved out of the clickable div to prevent bubbling issues */}
            {isOpen && !disabled && (!minSearchLength || searchQuery.length >= minSearchLength) && (
                <div className={`
                    absolute left-0 w-full overflow-hidden rounded-xl border border-border bg-popover shadow-xl z-[100] animate-in fade-in duration-200
                    ${openDirection === 'top' ? 'bottom-[calc(100%+4px)] slide-in-from-bottom-2' : 'top-[calc(100%+4px)] slide-in-from-top-2'}
                `}>
                    <div className="max-h-60 overflow-y-auto p-1 custom-scrollbar">
                        {filteredOptions.map((option, index) => {
                            const isSelected = multiple
                                ? (Array.isArray(value) && value.includes(option.value))
                                : value === option.value;

                            return (
                                <div
                                    key={option.value}
                                    onMouseEnter={() => setActiveIndex(index)}
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        handleSelect(option);
                                    }}
                                    className={`
                                        flex items-center justify-between px-3 py-2.5 text-sm rounded-lg cursor-pointer transition-colors mb-0.5 last:mb-0
                                        ${isSelected
                                            ? 'bg-primary/10 text-primary font-medium'
                                            : activeIndex === index
                                                ? 'bg-muted text-foreground'
                                                : 'text-muted-foreground hover:bg-muted/50'}
                                    `}
                                >
                                    <div className={`flex flex-col min-w-0 ${truncate ? 'truncate' : ''}`}>
                                        <span className={truncate ? 'truncate' : ''}>{option.label}</span>
                                        {option.description && (
                                            <span className={`text-[10px] text-slate-400 font-normal ${truncate ? 'truncate' : ''}`}>{option.description}</span>
                                        )}
                                    </div>
                                    {isSelected && <Check size={16} className="text-emerald-600 shrink-0" />}
                                </div>
                            );
                        })}

                        {filteredOptions.length === 0 && !loading && (
                            <div className="px-4 py-8 text-center">
                                <Search size={24} className="mx-auto text-slate-200 mb-2" />
                                <p className="text-sm text-slate-400 font-medium">
                                    {searchQuery ? noResultsText : noOptionsText}
                                </p>
                            </div>
                        )}

                        {loading && filteredOptions.length === 0 && (
                            <div className="px-4 py-8 text-center">
                                <Loader2 size={24} className="mx-auto text-primary/40 animate-spin mb-2" />
                                <p className="text-sm text-slate-400 font-medium">Buscando opções...</p>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {description && !error && <p className="text-[11px] text-slate-500 mt-1.5 ml-1">{description}</p>}
            {error && <p className="text-[11px] text-red-500 mt-1.5 ml-1 font-medium">{error}</p>}
        </div>
    );
};
