import React from 'react';

interface SwitchProps {
    label?: string;
    description?: string;
    error?: string;
    checked?: boolean;
    onCheckedChange?: (checked: boolean) => void;
    required?: boolean;
    disabled?: boolean;
    name?: string;
}

export const Switch: React.FC<SwitchProps> = ({
    label,
    description,
    error,
    checked,
    onCheckedChange,
    required,
    disabled,
    name
}) => {
    const [isFocused, setIsFocused] = React.useState(false);

    return (
        <div className="flex items-center gap-3">
            <button
                type="button"
                role="switch"
                id={name}
                aria-checked={checked}
                disabled={disabled}
                onClick={() => onCheckedChange?.(!checked)}
                onFocus={() => setIsFocused(true)}
                onBlur={() => setIsFocused(false)}
                className={`
        relative inline-flex h-6 w-11 shrink-0 cursor-pointer rounded-full border-2 border-transparent 
        transition-colors duration-200 ease-in-out focus-visible:outline-none focus-visible:ring-offset-2 focus-visible:ring-offset-white
        disabled:opacity-50 disabled:cursor-not-allowed
        ${isFocused ? 'ring-2 ring-primary ring-offset-2 ring-offset-white' : ''}
        ${checked ? 'bg-primary' : 'bg-slate-200'}
      `}
            >
                <span
                    className={`
          pointer-events-none block h-5 w-5 rounded-full bg-white shadow-lg ring-0 
          transition-transform duration-200 ease-in-out
          ${checked ? 'translate-x-5' : 'translate-x-0'}
        `}
                />
            </button>
            {label && (
                <label htmlFor={name} className="text-sm font-medium text-slate-700 cursor-pointer" onClick={() => !disabled && onCheckedChange?.(!checked)}>
                    {label}
                    {required && <span className="text-red-500 ml-1">*</span>}
                </label>
            )}
        </div>
    );
};
