import React from 'react';
import { FormElement } from '../../types';
import { AccordionItem } from '../../../ui/wireframe-ports/Accordion';
import { Input } from '../../../ui/wireframe-ports/Input';
import { Switch } from '../../../ui/fields/Switch';

interface StaticPropertiesProps {
    element: FormElement;
    onChange: (key: keyof FormElement, value: any) => void;
}

export const StaticProperties: React.FC<StaticPropertiesProps> = ({ element, onChange }) => {
    return (
        <div className="px-5">
            <AccordionItem title="Static Content" defaultOpen>
                <div className="space-y-4 pt-2">
                    <Input
                        label="Name/ID"
                        value={element.name || ''}
                        onChange={(e) => onChange('name', e.target.value)}
                    />

                    {['h1', 'h2', 'h3', 'h4', 'p', 'quote', 'link'].includes(element.type) && (
                        <div className="w-full">
                            <label className="text-xs font-medium mb-1.5 block text-slate-700">Content</label>
                            <textarea
                                className="flex w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm shadow-sm placeholder:text-slate-400 focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-primary disabled:cursor-not-allowed disabled:opacity-50 resize-none h-24"
                                value={element.content || ''}
                                onChange={(e) => onChange('content', e.target.value)}
                            />
                        </div>
                    )}

                    {element.type === 'link' && (
                        <>
                            <Input label="Href" value={element.href || ''} onChange={(e) => onChange('href', e.target.value)} />
                            <Input label="Target" value={element.target || '_blank'} onChange={(e) => onChange('target', e.target.value)} />
                        </>
                    )}

                    {element.type === 'image' && (
                        <>
                            <Input label="Source URL" value={element.src || element.content || ''} onChange={(e) => {
                                onChange('src', e.target.value);
                                // Also sync content for older systems/expressions
                                onChange('content', e.target.value);
                            }} />

                            {(element.src || element.content) && (
                                <div className="mt-2 p-2 border border-slate-100 rounded-md bg-white">
                                    <p className="text-[10px] font-bold text-slate-400 uppercase mb-2">Internal Preview</p>
                                    <img
                                        src={element.src || element.content}
                                        className="max-w-full h-auto rounded border border-slate-200"
                                        alt="Thumbnail preview"
                                        onError={(e) => {
                                            (e.target as HTMLImageElement).src = 'https://via.placeholder.com/150?text=Invalid+URL';
                                        }}
                                    />
                                </div>
                            )}

                            <Input label="Alt text" value={element.alt || ''} onChange={(e) => onChange('alt', e.target.value)} />
                            <div className="grid grid-cols-2 gap-4">
                                <Input label="Width" value={element.width || ''} onChange={(e) => onChange('width', e.target.value)} />
                                <Input label="Height" value={element.height || ''} onChange={(e) => onChange('height', e.target.value)} />
                            </div>
                        </>
                    )}

                    {element.type === 'static-html' && (
                        <div className="w-full">
                            <label className="text-xs font-medium mb-1.5 block text-slate-700">HTML Code</label>
                            <textarea
                                className="flex w-full rounded-md border border-slate-300 bg-slate-900 text-emerald-400 p-3 text-xs font-mono shadow-sm focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-primary h-40"
                                value={element.html || ''}
                                onChange={(e) => onChange('html', e.target.value)}
                            />
                        </div>
                    )}
                </div>
            </AccordionItem>

            <AccordionItem title="Advanced">
                <div className="space-y-4 pt-4">
                    <div className="flex items-center justify-between">
                        <label className="text-xs text-slate-700">Use expression</label>
                        <Switch
                            checked={element.useExpressionValue || false}
                            onCheckedChange={(c) => onChange('useExpressionValue', c)}
                        />
                    </div>
                    {element.useExpressionValue && (
                        <Input
                            label="Expression"
                            value={element.expression || ''}
                            placeholder="{{ field_name * 2 }}"
                            onChange={(e) => onChange('expression', e.target.value)}
                        />
                    )}
                </div>
            </AccordionItem>
        </div>
    );
};
