
import { differenceInYears, parseISO, isValid, format, intervalToDuration } from 'date-fns';

/**
 * Built-in functions for expressions
 */
export const builtinFunctions: Record<string, Function> = {
    SUM: (...args: any[]) => args.reduce((a, b) => Number(a || 0) + Number(b || 0), 0),
    AVG: (...args: any[]) => args.length ? builtinFunctions.SUM(...args) / args.length : 0,
    MIN: (...args: any[]) => Math.min(...args.map(v => Number(v || 0))),
    MAX: (...args: any[]) => Math.max(...args.map(v => Number(v || 0))),
    COUNT: (arr: any) => Array.isArray(arr) ? arr.length : 0,
    ROUND: (val: any) => Math.round(Number(val || 0)),
    AGE: (date: any) => {
        if (!date) return '';
        const d = typeof date === 'string' ? parseISO(date) : date;
        return isValid(d) ? differenceInYears(new Date(), d) : '';
    },
    FULL_AGE: (date: any) => {
        if (!date) return '';
        const d = typeof date === 'string' ? parseISO(date) : date;
        if (!isValid(d)) return '';
        const dur = intervalToDuration({ start: d, end: new Date() });
        const parts = [];
        if (dur.years) parts.push(`${dur.years}y`);
        if (dur.months) parts.push(`${dur.months}m`);
        if (dur.days) parts.push(`${dur.days}d`);
        return parts.join(' ') || '0d';
    },
    TODAY: () => format(new Date(), 'yyyy-MM-dd'),
    NOW: () => format(new Date(), 'yyyy-MM-dd HH:mm:ss'),
    EMPTY: (val: any) => val === undefined || val === null || val === '' || (Array.isArray(val) && val.length === 0),
    NOT_EMPTY: (val: any) => !builtinFunctions.EMPTY(val),
    NOT: (val: any) => !val,
    PI: () => Math.PI,
    E: () => Math.E,
};

/**
 * Helper to get value from a nested object path
 */
function getPathValue(obj: any, path: string) {
    if (!path || !obj) return undefined;

    // Support for both dot notation and array indexing: field[0].name or field.0.name
    const parts = path.split(/\.|\[|\]/).filter(Boolean);
    return parts.reduce((acc, part) => acc && acc[part], obj);
}

/**
 * Evaluates a string containing placeholders {field} or JS blocks ${1+1}
 */
export function evaluateFormExpression(
    expression: string,
    values: Record<string, any>,
    customFunctions: Record<string, Function> = {}
): string {
    if (!expression) return '';

    const allFunctions = { ...builtinFunctions, ...customFunctions };
    let result = expression;

    // Helper to evaluate a JS block
    const evalJS = (jsExpr: string) => {
        try {
            const keys = Object.keys(values);
            const funcKeys = Object.keys(allFunctions);
            const allKeys = [...keys, ...funcKeys];
            const allValues = [...Object.values(values), ...Object.values(allFunctions)];

            const fn = new Function(...allKeys, `return ${jsExpr}`);
            const val = fn(...allValues);
            return val !== undefined ? String(val) : '';
        } catch (e) {
            console.error('Expression error (${}):', e);
            return '';
        }
    };

    // Helper to evaluate a placeholder {field} or {FUNC()}
    const evalPlaceholder = (content: string) => {
        const trimmed = content.trim();
        const funcMatch = trimmed.match(/^([A-Z_0-9]+)\((.*)\)$/);

        if (funcMatch) {
            const funcName = funcMatch[1];
            const argsStr = funcMatch[2];

            if (allFunctions[funcName]) {
                const args = argsStr.split(',').map((s: string) => {
                    const arg = s.trim();
                    if (arg.startsWith("'") || arg.startsWith('"')) return arg.slice(1, -1);
                    if (!isNaN(Number(arg))) return Number(arg);
                    const val = getPathValue(values, arg);
                    return val; // Returns undefined if not found, allowing function to handle it
                });
                const res = allFunctions[funcName](...args);
                return res !== undefined && res !== null ? String(res) : '';
            }
        }

        const val = getPathValue(values, trimmed);
        return val !== undefined && val !== null ? String(val) : '';
    };

    // Process blocks manually to handle nested braces
    let i = 0;
    while (i < result.length) {
        if (result.substring(i, i + 2) === '${') {
            let start = i;
            let depth = 1;
            let end = -1;
            for (let j = i + 2; j < result.length; j++) {
                if (result[j] === '{') depth++;
                if (result[j] === '}') {
                    depth--;
                    if (depth === 0) {
                        end = j;
                        break;
                    }
                }
            }
            if (end !== -1) {
                const jsExpr = result.substring(start + 2, end);
                const evaluated = evalJS(jsExpr);
                result = result.substring(0, start) + evaluated + result.substring(end + 1);
                i += evaluated.length;
                continue;
            }
        } else if (result[i] === '{' && (i === 0 || result[i - 1] !== '$')) {
            let start = i;
            let depth = 1;
            let end = -1;
            for (let j = i + 1; j < result.length; j++) {
                if (result[j] === '{') depth++;
                if (result[j] === '}') {
                    depth--;
                    if (depth === 0) {
                        end = j;
                        break;
                    }
                }
            }
            if (end !== -1) {
                const content = result.substring(start + 1, end);
                const evaluated = evalPlaceholder(content);
                result = result.substring(0, start) + evaluated + result.substring(end + 1);
                i += evaluated.length;
                continue;
            }
        }
        i++;
    }

    return result;
}
