import React from 'react';
import { FormElement } from '../../types';
import { PhoneInput } from '../../../ui/fields/PhoneInput';
import { useFormContext } from 'react-hook-form';

interface PhoneRendererProps {
    element: FormElement;
    prefix?: string;
    config?: any;
}

export const PhoneRenderer: React.FC<PhoneRendererProps> = ({
    element,
    prefix = '',
    config
}) => {
    const { watch, setValue, formState: { errors } } = useFormContext();
    const fieldName = prefix
        ? `${prefix}${element.name ? `.${element.name}` : ''}`
        : element.name || `element_${element.id.replace(/-/g, '_')}`;

    const error = errors[fieldName]?.message as string | undefined;
    const value = watch(fieldName);
    const globalSize = config?.layout?.size || 'md';

    return (
        <PhoneInput
            key={element.id}
            error={error}
            value={value}
            disabled={element.disabled || element.readOnly}
            placeholder={element.placeholder}
            size={element.size || globalSize}
            unmaskValue={element.unmaskValue}
            onChange={(val) => setValue(fieldName, val, { shouldValidate: true })}
        />
    );
};
