import React from 'react';
import { FormElement } from '../../types';
import { Checkbox } from '../../../ui/fields/Checkbox';
import { useFormContext } from 'react-hook-form';

interface CheckboxRendererProps {
    element: FormElement;
    prefix?: string;
}

export const CheckboxRenderer: React.FC<CheckboxRendererProps> = ({
    element,
    prefix = ''
}) => {
    const { register, watch, setValue, formState: { errors } } = useFormContext();
    const fieldName = prefix
        ? `${prefix}${element.name ? `.${element.name}` : ''}`
        : element.name || `element_${element.id.replace(/-/g, '_')}`;

    const error = errors[fieldName]?.message as string | undefined;
    const value = watch(fieldName);

    return (
        <Checkbox
            key={element.id}
            error={error}
            label={element.checkboxLabel || 'Checkbox'}
            checked={value || false}
            onCheckedChange={(checked) => setValue(fieldName, checked, { shouldValidate: true })}
        />
    );
};
