import React, { useState } from 'react';
import { ChevronDown } from 'lucide-react';

interface AccordionItemProps {
  title: string;
  children: React.ReactNode;
  defaultOpen?: boolean;
}

export const AccordionItem: React.FC<AccordionItemProps> = ({ title, children, defaultOpen = false }) => {
  const [isOpen, setIsOpen] = useState(defaultOpen);

  return (
    <div className="border-b border-slate-200 last:border-0 overflow-hidden">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`flex w-full items-center justify-between px-4 py-3 text-[11px] font-bold transition-all text-slate-700 bg-slate-50/80 hover:bg-slate-100/80 ${isOpen ? 'border-b border-slate-100' : ''}`}
      >
        <span className="uppercase tracking-wide">{title}</span>
        <ChevronDown
          className={`h-3.5 w-3.5 shrink-0 transition-transform duration-200 text-slate-400 ${isOpen ? 'rotate-180' : ''}`}
        />
      </button>
      {isOpen && <div className="p-0 transition-all">{children}</div>}
    </div>
  );
};