import React from 'react';
import { FormElement } from '../../types';
import { Type, PenTool, ShieldCheck } from 'lucide-react';

interface AdvancedCanvasProps {
    element: FormElement;
    isSelected: boolean;
}

export const AdvancedCanvas: React.FC<AdvancedCanvasProps> = ({ element, isSelected }) => {
    switch (element.type) {
        case 'wysiwyg':
            return (
                <div className={`w-full border rounded-md bg-white overflow-hidden ${isSelected ? 'border-primary' : 'border-slate-300'}`}>
                    <div className="bg-slate-50 border-b border-slate-200 p-2 flex gap-2">
                        <div className="w-6 h-6 rounded bg-white border border-slate-200 flex items-center justify-center text-xs font-bold font-serif">B</div>
                        <div className="w-6 h-6 rounded bg-white border border-slate-200 flex items-center justify-center text-xs italic font-serif">I</div>
                        <div className="w-6 h-6 rounded bg-white border border-slate-200 flex items-center justify-center text-xs underline font-serif">U</div>
                    </div>
                    <div className="p-3 min-h-[100px] text-slate-400 text-sm">
                        {element.placeholder || 'Write something rich...'}
                    </div>
                </div>
            );

        case 'signature':
            return (
                <div className={`w-full border rounded-md bg-slate-50 border-dashed flex flex-col items-center justify-center py-8 gap-2 ${isSelected ? 'border-primary' : 'border-slate-300'}`}>
                    <PenTool size={20} className="text-slate-400" />
                    <span className="text-xs text-slate-400 font-medium">Draw your signature here</span>
                </div>
            );

        case 'captcha':
            return (
                <div className={`w-full bg-slate-50 border border-slate-200 rounded p-4 flex items-center justify-between ${isSelected ? 'border-primary' : ''}`}>
                    <div className="flex items-center gap-3">
                        <div className="w-5 h-5 border-2 border-slate-300 rounded bg-white" />
                        <span className="text-sm font-medium text-slate-700">I'm not a robot</span>
                    </div>
                    <div className="flex flex-col items-center opacity-40">
                        <ShieldCheck size={20} />
                        <span className="text-[8px] font-bold uppercase tracking-widest mt-0.5">reCAPTCHA</span>
                    </div>
                </div>
            );

        default:
            return null;
    }
};
