import React from 'react';
import { FormElement } from '../../types';
import { BaseProperties } from '../common/BaseProperties';
import { Input } from '../../../ui/wireframe-ports/Input';
import { Switch } from '../../../ui/fields/Switch';

interface TogglePropertiesProps {
    element: FormElement;
    onChange: (key: keyof FormElement, value: any) => void;
}

export const ToggleProperties: React.FC<TogglePropertiesProps> = ({ element, onChange }) => {
    return (
        <div className="px-5">
            <BaseProperties element={element} onChange={onChange} showPlaceholder={false} />
            <div className="space-y-4 pt-4">
                <Input
                    label="Toggle text"
                    value={element.toggleText || ''}
                    onChange={(e) => onChange('toggleText', e.target.value)}
                />
                <div className="grid grid-cols-2 gap-2">
                    <Input
                        label="On Label"
                        value={element.toggleOnLabel || ''}
                        onChange={(e) => onChange('toggleOnLabel', e.target.value)}
                    />
                    <Input
                        label="Off Label"
                        value={element.toggleOffLabel || ''}
                        onChange={(e) => onChange('toggleOffLabel', e.target.value)}
                    />
                </div>
                <div className="flex items-center justify-between">
                    <label className="text-xs text-slate-700">Selected by default</label>
                    <Switch
                        checked={element.selectedByDefault || false}
                        onCheckedChange={(c) => onChange('selectedByDefault', c)}
                    />
                </div>
            </div>
        </div>
    );
};
