import React from 'react';
import { FormElement } from '../../types';
import { BaseProperties } from '../common/BaseProperties';
import { AccordionItem } from '../../../ui/wireframe-ports/Accordion';
import { Input } from '../../../ui/wireframe-ports/Input';
import { Switch } from '../../../ui/fields/Switch';
import { Info } from 'lucide-react';

interface FilePropertiesProps {
    element: FormElement;
    onChange: (key: keyof FormElement, value: any) => void;
}

export const FileProperties: React.FC<FilePropertiesProps> = ({ element, onChange }) => {
    return (
        <div className="px-5">
            <BaseProperties element={element} onChange={onChange} />

            <AccordionItem title="Upload options" defaultOpen>
                <div className="space-y-4 pt-2">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-1">
                            <label className="text-xs text-slate-700">Can Sort</label>
                            <Info size={12} className="text-slate-400" />
                        </div>
                        <Switch
                            checked={element.fileCanSort || false}
                            onCheckedChange={(c) => onChange('fileCanSort', c)}
                        />
                    </div>
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-1">
                            <label className="text-xs text-slate-700">Clickable</label>
                            <Info size={12} className="text-slate-400" />
                        </div>
                        <Switch
                            checked={element.fileClickable !== false}
                            onCheckedChange={(c) => onChange('fileClickable', c)}
                        />
                    </div>
                </div>
            </AccordionItem>

            <AccordionItem title="URLS">
                <div className="space-y-4 pt-2">
                    <div className="grid grid-cols-[80px_1fr] gap-4 items-center">
                        <label className="text-xs text-slate-700">Click URL</label>
                        <Input
                            value={element.fileClickUrl || ''}
                            onChange={(e) => onChange('fileClickUrl', e.target.value)}
                            className="bg-slate-50"
                        />
                    </div>
                    <div className="grid grid-cols-[80px_1fr] gap-4 items-center">
                        <label className="text-xs text-slate-700">Preview URL</label>
                        <Input
                            value={element.filePreviewUrl || ''}
                            onChange={(e) => onChange('filePreviewUrl', e.target.value)}
                            className="bg-slate-50"
                        />
                    </div>
                </div>
            </AccordionItem>
        </div>
    );
};
