import React from 'react';
import { FormElement } from '../../types';
import { BaseProperties } from '../common/BaseProperties';
import { AccordionItem } from '../../../ui/wireframe-ports/Accordion';
import { Input } from '../../../ui/wireframe-ports/Input';

interface SlidersPropertiesProps {
    element: FormElement;
    onChange: (key: keyof FormElement, value: any) => void;
}

export const SlidersProperties: React.FC<SlidersPropertiesProps> = ({ element, onChange }) => {
    return (
        <div className="px-5">
            <BaseProperties element={element} onChange={onChange} />

            <AccordionItem title="Slider settings" defaultOpen>
                <div className="space-y-4 pt-2">
                    <div className="grid grid-cols-2 gap-4">
                        <Input
                            label="Min"
                            type="number"
                            value={element.min || element.sliderMin || 0}
                            onChange={(e) => onChange('sliderMin', parseInt(e.target.value))}
                        />
                        <Input
                            label="Max"
                            type="number"
                            value={element.max || element.sliderMax || 100}
                            onChange={(e) => onChange('sliderMax', parseInt(e.target.value))}
                        />
                    </div>
                    <Input
                        label="Step"
                        type="number"
                        value={element.step || element.sliderStep || 1}
                        onChange={(e) => onChange('sliderStep', parseInt(e.target.value))}
                    />
                    {element.type === 'range-slider' && (
                        <div className="grid grid-cols-2 gap-4">
                            <Input
                                label="Prefix"
                                value={element.sliderFormatPrefix || ''}
                                onChange={(e) => onChange('sliderFormatPrefix', e.target.value)}
                            />
                            <Input
                                label="Suffix"
                                value={element.sliderFormatSuffix || ''}
                                onChange={(e) => onChange('sliderFormatSuffix', e.target.value)}
                            />
                        </div>
                    )}
                </div>
            </AccordionItem>
        </div>
    );
};
