import React, { useState } from 'react';

interface PhoneInputProps {
    value?: string;
    onChange?: (value: string) => void; // Expects full string e.g. "+1 5550123"
    onBlur?: () => void;
    name?: string;
    label?: string;
    description?: string;
    error?: string;
    required?: boolean;
    disabled?: boolean;
    placeholder?: string;
    defaultCountry?: string; // e.g. "BR", "US"
    size?: 'sm' | 'md' | 'lg' | 'default';
    unmaskValue?: boolean;
}

export const COUNTRIES = [
    { code: '1', flag: '🇺🇸', label: 'US' },
    { code: '55', flag: '🇧🇷', label: 'BR' },
    { code: '234', flag: '🇳🇬', label: 'NG' },
    { code: '351', flag: '🇵🇹', label: 'PT' },
    { code: '44', flag: '🇬🇧', label: 'UK' },
    { code: '33', flag: '🇫🇷', label: 'FR' },
    { code: '49', flag: '🇩🇪', label: 'DE' },
];

export const PhoneInput: React.FC<PhoneInputProps> = ({
    value = '',
    onChange,
    onBlur,
    name,
    label,
    description,
    error,
    required,
    disabled = false,
    placeholder,
    defaultCountry,
    size = 'default',
    unmaskValue = false
}) => {
    const getCodeFromIso = (iso: string) => {
        const country = COUNTRIES.find(c => c.label === iso);
        return country ? country.code : '1';
    };

    const [countryCode, setCountryCode] = useState(() => getCodeFromIso(defaultCountry || 'US'));
    const [localNumber, setLocalNumber] = useState('');
    const [isFocused, setIsFocused] = useState(false);

    React.useEffect(() => {
        if (!value) {
            // If value is cleared, reset to default country
            setCountryCode(getCodeFromIso(defaultCountry || 'US'));
            setLocalNumber('');
            return;
        }

        // Check if value starts with a known country code
        // value format assumed: "+{code} {number}" or "+{code}{number}"
        const cleanVal = value.replace('+', '');
        const matchedCountry = COUNTRIES.find(c => cleanVal.startsWith(c.code));

        if (matchedCountry) {
            setCountryCode(matchedCountry.code);
            // Remove code from start
            let num = cleanVal.slice(matchedCountry.code.length).trim();
            setLocalNumber(num);
        } else {
            // Fallback: assume default is US or just raw text
            setLocalNumber(value);
        }
    }, [value]);

    const handleCountryChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const newCode = e.target.value;
        setCountryCode(newCode);
        triggerChange(newCode, localNumber);
    };

    const handleNumberChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const newNum = e.target.value;
        setLocalNumber(newNum);
        triggerChange(countryCode, newNum);
    };

    const triggerChange = (code: string, num: string) => {
        if (onChange) {
            onChange(`+${code} ${num}`);
        }
    };

    return (
        <div className="w-full">
            {label && (
                <label className="text-sm font-medium mb-1.5 block text-slate-700">
                    {label}
                    {required && <span className="text-red-500 ml-1">*</span>}
                </label>
            )}

            <div className={`flex w-full rounded-md border bg-muted/30 shadow-sm transition-colors ${error ? 'border-red-500' : isFocused ? 'border-primary ring-1 ring-primary/20' : 'border-border/50'} ${disabled ? 'bg-muted opacity-60 cursor-not-allowed' : ''} ${size === 'sm' ? 'h-8' : size === 'lg' ? 'h-12' : 'h-10'}`} onFocus={() => setIsFocused(true)} onBlur={() => setIsFocused(false)}>
                {/* Country Select (Flag only) */}
                <div className="relative border-r border-border/50">
                    <select
                        value={countryCode}
                        onChange={handleCountryChange}
                        disabled={disabled}
                        className={`${size === 'sm' ? 'h-7' : size === 'lg' ? 'h-11' : 'h-9'} appearance-none bg-transparent pl-3 pr-8 text-lg hover:bg-slate-50 focus:outline-none cursor-pointer`}
                    >
                        {COUNTRIES.map(c => (
                            <option key={c.code} value={c.code}>
                                {c.flag}
                            </option>
                        ))}
                    </select>
                    {/* Custom Arrow */}
                    <div className="pointer-events-none absolute right-2 top-0 bottom-0 flex items-center text-slate-400">
                        <svg className="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
                    </div>
                </div>

                {/* Country Code Display */}
                <div className="flex items-center justify-center px-3 bg-muted/50 text-muted-foreground text-sm font-medium border-r border-border/50 select-none">
                    +{countryCode}
                </div>

                {/* Number Input */}
                <input
                    type="tel"
                    value={localNumber}
                    onChange={handleNumberChange}
                    onBlur={onBlur}
                    disabled={disabled}
                    placeholder={placeholder || '000 000 000'}
                    className="flex-1 border-0 bg-transparent px-3 text-sm placeholder:text-muted-foreground/40 focus:outline-none focus:ring-0"
                />
            </div>

            {description && !error && (
                <p className="text-xs text-slate-500 mt-1">{description}</p>
            )}
            {error && (
                <p className="text-xs text-red-500 mt-1">{error}</p>
            )}
        </div>
    );
};
