import React from 'react';
import { FormElement } from '../../types';

interface CheckboxCanvasProps {
    element: FormElement;
    isSelected: boolean;
}

export const CheckboxCanvas: React.FC<CheckboxCanvasProps> = ({ element, isSelected }) => {
    const isSingle = element.type === 'checkbox';

    if (isSingle) {
        return (
            <div className={`flex items-center gap-2 ${element.align === 'center' ? 'justify-center' : element.align === 'right' ? 'justify-end' : ''}`}>
                <div className={`h-4 w-4 rounded border ${isSelected ? 'border-primary' : 'border-slate-300'} bg-white flex items-center justify-center ${element.selectedByDefault ? 'bg-primary border-primary' : ''}`}>
                    {element.selectedByDefault && <svg width="10" height="8" viewBox="0 0 10 8" fill="none" className="text-white"><path d="M1 4L3.5 6.5L9 1" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" /></svg>}
                </div>
                <span className="text-sm text-slate-700">{element.checkboxLabel || 'Checkbox'}</span>
            </div>
        );
    }

    if (element.view === 'tabs' || element.type === 'checkbox-tabs') {
        return (
            <div className="flex w-full rounded-md border border-slate-200 bg-slate-50 p-1">
                {(element.options || [{ label: 'Option 1' }, { label: 'Option 2' }]).map((opt, i) => (
                    <div key={i} className={`flex-1 py-1.5 text-center text-[10px] font-bold rounded ${i === 0 ? 'bg-white shadow-sm text-slate-900 border border-slate-200' : 'text-slate-400 opacity-60'}`}>
                        {opt.label}
                    </div>
                ))}
            </div>
        );
    }

    if (element.view === 'blocks' || element.type === 'checkbox-blocks') {
        return (
            <div className="space-y-2">
                {(element.options || [{ label: 'Option 1', description: '' }, { label: 'Option 2', description: '' }]).map((opt: any, i: number) => (
                    <div key={i} className={`flex items-center gap-3 p-3 rounded-md border bg-white ${isSelected ? 'border-primary shadow-sm' : 'border-slate-200'}`}>
                        <div className={`h-4 w-4 rounded border border-slate-300 shrink-0`}></div>
                        <div className="flex flex-col">
                            <span className="text-sm font-medium text-slate-900 leading-none">{opt.label}</span>
                            {opt.description && <span className="text-[10px] text-slate-400 mt-1">{opt.description}</span>}
                        </div>
                    </div>
                ))}
            </div>
        );
    }

    // Default Group View
    return (
        <div className="flex flex-wrap gap-4">
            {(element.options || [{ label: 'Option 1' }, { label: 'Option 2' }]).map((opt, i) => (
                <div key={i} className="flex items-center gap-2">
                    <div className="h-4 w-4 rounded border border-slate-300 bg-white"></div>
                    <span className="text-sm text-slate-700">{opt.label}</span>
                </div>
            ))}
        </div>
    );
};
