import React from 'react';

interface TextAreaProps extends React.TextareaHTMLAttributes<HTMLTextAreaElement> {
    label?: string;
    error?: string;
    description?: string;
    before?: string;
    between?: string;
    after?: string;
    size?: 'default' | 'sm' | 'md' | 'lg';
}

export const TextArea = React.forwardRef<HTMLTextAreaElement, TextAreaProps>(
    ({ className, label, error, description, before, between, after, size = 'md', ...props }, ref) => {
        const [isFocused, setIsFocused] = React.useState(false);

        const sizeClasses = {
            sm: 'text-xs px-2 py-1.5 min-h-[60px]',
            md: 'text-sm px-3 py-2 min-h-[80px]',
            lg: 'text-base px-4 py-3 min-h-[120px]',
            default: 'text-sm px-3 py-2 min-h-[80px]'
        };

        const currentSizeClass = sizeClasses[size as keyof typeof sizeClasses] || sizeClasses.md;

        return (
            <textarea
                className={`flex w-full rounded-md border bg-muted/30 shadow-sm placeholder:text-muted-foreground/40 focus-visible:outline-none disabled:cursor-not-allowed disabled:opacity-50 ${error ? 'border-red-500' : isFocused ? 'border-primary ring-1 ring-primary/20' : 'border-border/50'} ${currentSizeClass} ${className || ''}`}
                ref={ref}
                onFocus={() => setIsFocused(true)}
                onBlur={() => setIsFocused(false)}
                {...props}
            />
        );
    }
);
TextArea.displayName = "TextArea";
