import React from 'react';
import { Select } from '@/components/ui/fields/Select';
import { MultiSelect } from '@/components/ui/fields/MultiSelect';
import { RadioGroup } from '@/components/ui/fields/RadioGroup';
import { CheckboxGroup } from '@/components/ui/fields/CheckboxGroup';
import { TopOfMindField } from '@/components/ui/fields/TopOfMindField';
import { FormElement } from '@/components/form-engine/types';
import { useFetchOptions } from '../hooks/useFetchOptions';

interface SmartFieldRendererProps {
    element: FormElement;
    value: any;
    onChange: (val: any) => void;
    error?: string;
    fieldName?: string;
}

/**
 * SmartFieldRenderer handles Data Sources (List, JSON, Endpoint, Internal)
 * for multiple field types: Select, MultiSelect, RadioGroups, CheckboxGroups, TopOfMind.
 */
export const SmartFieldRenderer: React.FC<SmartFieldRendererProps> = ({
    element,
    value,
    onChange,
    error,
    fieldName = element.name || element.id
}) => {
    const { options, loading, refetch } = useFetchOptions(element);

    const handleSearchChange = (query: string) => {
        if (element.updateOptionsOnSearch) {
            refetch(query);
        }
    };

    const handleValueChange = (val: any) => {
        if (element.useObjectValue && val) {
            const isMultiple = Array.isArray(val) || element.type.includes('multiselect') || element.type.includes('checkbox') || element.type.includes('tags');

            if (isMultiple) {
                const currentVals = Array.isArray(val) ? val : [val];
                const fullOptions = currentVals.map(v => options.find(opt => opt.value === v) || { value: v, label: v });
                onChange(fullOptions);
            } else {
                const fullOption = options.find(opt => opt.value === val);
                onChange(fullOption || val);
            }
            return;
        }
        onChange(val);
    };

    const getUiValue = () => {
        if (!element.useObjectValue || !value) return value;
        const isMultiple = Array.isArray(value);
        if (isMultiple) {
            return value.map((v: any) => (typeof v === 'object' ? v.value : v));
        }
        return (typeof value === 'object') ? value.value : value;
    };

    const uiValue = getUiValue();

    // Common props for basic inputs
    const commonProps = {
        label: element.label,
        description: element.description,
        placeholder: element.placeholder,
        error: error,
        disabled: element.disabled,
        required: element.required,
        loading: loading,
        name: fieldName,
        options: options
    };

    // Determine specific view for Radio/Checkbox
    let view: 'default' | 'blocks' | 'tabs' = 'default';
    if (element.view && ['default', 'blocks', 'tabs'].includes(element.view)) view = element.view as any;
    else if (element.type.includes('-blocks')) view = 'blocks';
    else if (element.type.includes('-tabs')) view = 'tabs';

    switch (element.type) {
        case 'select':
            return (
                <Select
                    {...commonProps}
                    value={uiValue || ''}
                    onChange={handleValueChange}
                    searchable={element.search !== false}
                    onSearchChange={element.search !== false ? handleSearchChange : undefined}
                    {...getAdvancedSelectProps(element)}
                />
            );

        case 'multiselect':
        case 'tags':
            return (
                <MultiSelect
                    {...commonProps}
                    value={Array.isArray(uiValue) ? uiValue : []}
                    onValueChange={handleValueChange}
                    {...getAdvancedSelectProps(element)}
                />
            );

        case 'top-of-mind':
            return (
                <TopOfMindField
                    {...commonProps}
                    value={uiValue}
                    onChange={handleValueChange}
                    onSearchChange={handleSearchChange}
                    allowCustomValue={element.allowCustomValue}
                    strictSearch={element.strictSearch}
                    trackBy={element.trackByKey}
                    displayCaret={element.displayCaret}
                    truncate={element.truncate}
                    openDirection={element.openDirection}
                    optionLimit={element.optionLimit}
                    canDeselect={element.canDeselect}
                    canClear={element.canClear}
                    closeOnSelect={element.closeOnSelect}
                    updateOptionsOnSearch={element.updateOptionsOnSearch}
                // Pass data source props effectively since TopOfMind internally might use them if not careful, 
                // but we already use the hook here. 
                // However, TopOfMindField (the UI component) might have its own logic we want to leverage.
                />
            );

        case 'radio-group':
        case 'radio-blocks':
        case 'radio-tabs':
            return (
                <RadioGroup
                    {...commonProps}
                    value={uiValue}
                    onValueChange={handleValueChange}
                    view={view}
                    direction={(view === 'blocks') ? 'vertical' : 'vertical'} // Adjust as needed
                />
            );

        case 'checkbox-group':
        case 'checkbox-blocks':
        case 'checkbox-tabs':
            return (
                <CheckboxGroup
                    {...commonProps}
                    value={Array.isArray(uiValue) ? uiValue : []}
                    onValueChange={handleValueChange}
                    view={view}
                    direction={(view === 'blocks') ? 'vertical' : 'vertical'} // Adjust as needed
                />
            );

        default:
            return <div className="text-red-500 text-xs text-secondary-foreground italic">Unsupported Smart Field: {element.type}</div>;
    }
};

// Helper to extract advanced select props from element
function getAdvancedSelectProps(element: FormElement) {
    return {
        strictSearch: element.strictSearch,
        trackBy: element.trackByKey,
        allowNewOption: element.allowNewOption,
        appendNewOption: element.appendNewOption,
        addOn: element.addOn,
        canDeselect: element.canDeselect,
        closeOnSelect: element.closeOnSelect,
        displayCaret: element.displayCaret !== false,
        truncate: element.truncate !== false,
        openDirection: element.openDirection,
        optionLimit: element.optionLimit,
        noOptionsText: element.noOptionsText,
        noResultsText: element.noResultsText,
        canClear: element.canClear !== false,
        inputType: element.inputTypeSelect,
        autoComplete: element.autocompleteSelect,
    };
}
