import { useState, useEffect, useCallback, useMemo } from 'react';
import { FormElement, SelectOption } from '../types';

export function useFetchOptions(element: FormElement) {
    const [options, setOptions] = useState<SelectOption[]>(element.options || []);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const fetchOptions = useCallback(async (query: string = '') => {
        const isRemote = element.dataSourceType === 'endpoint' || element.dataSourceType === 'internal';

        if (!isRemote || !element.dataSourceUrl) {
            return;
        }

        setLoading(true);
        setError(null);
        try {
            let url = element.dataSourceUrl;
            if (element.searchParam && query) {
                const separator = url.includes('?') ? '&' : '?';
                url += `${separator}${element.searchParam}=${encodeURIComponent(query)}`;
            }

            const response = await fetch(url);
            if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
            const data = await response.json();

            let items = element.dataSourceDataKey ? (data[element.dataSourceDataKey] || []) : data;

            if (!Array.isArray(items)) {
                items = [];
            }

            const mappedOptions: SelectOption[] = items.map((item: any) => {
                if (typeof item === 'string') return { label: item, value: item };
                return {
                    label: element.dataSourceLabelKey ? item[element.dataSourceLabelKey] : (item.label || item.name || String(item)),
                    value: element.dataSourceValueKey ? String(item[element.dataSourceValueKey]) : (String(item.value || item.id || item)),
                    description: element.dataSourceDescriptionKey ? item[element.dataSourceDescriptionKey] : item.description,
                    // Preserve aliases for TopOfMind if they exist in the source
                    aliases: item.aliases || item.alias,
                    ...item
                };
            });

            setOptions(mappedOptions);
        } catch (err) {
            console.error(`[useFetchOptions] Failed to fetch options for ${element.name || element.id}:`, err);
            setError(err instanceof Error ? err.message : 'Failed to fetch options');
        } finally {
            setLoading(false);
        }
    }, [
        element.dataSourceType,
        element.dataSourceUrl,
        element.searchParam,
        element.dataSourceDataKey,
        element.dataSourceLabelKey,
        element.dataSourceValueKey,
        element.dataSourceDescriptionKey,
        element.name,
        element.id
    ]);

    // Initial load and sync with static options
    useEffect(() => {
        if (element.dataSourceType === 'endpoint' || element.dataSourceType === 'internal') {
            fetchOptions();
        } else if (element.dataSourceType === 'json' && element.dataSourceJson) {
            try {
                const parsed = JSON.parse(element.dataSourceJson);
                setOptions(Array.isArray(parsed) ? parsed : []);
            } catch (err) {
                console.error('[useFetchOptions] Failed to parse JSON data source:', err);
                setOptions([]);
            }
        } else {
            setOptions(element.options || []);
        }
    }, [
        element.dataSourceType,
        element.dataSourceUrl,
        element.dataSourceJson,
        element.options,
        fetchOptions
    ]);

    return {
        options,
        loading,
        error,
        refetch: fetchOptions
    };
}
