import React from 'react';

interface CheckboxProps {
    label?: string;
    error?: string;
    description?: string;
    checked?: boolean;
    onCheckedChange?: (checked: boolean) => void;
    required?: boolean;
    disabled?: boolean;
}

export const Checkbox = React.forwardRef<HTMLInputElement, CheckboxProps>(
    ({ label, error, description, checked, onCheckedChange, required, disabled }, ref) => {
        return (
            <div className="flex items-start gap-2">
                <input
                    type="checkbox"
                    ref={ref}
                    checked={checked}
                    onChange={(e) => onCheckedChange?.(e.target.checked)}
                    disabled={disabled}
                    className="mt-1 h-4 w-4 rounded border-slate-300 text-primary accent-primary focus:ring-2 focus:ring-primary disabled:cursor-not-allowed disabled:opacity-50"
                />
                {label && (
                    <label className="text-sm text-slate-700 cursor-pointer select-none">
                        {label}
                        {required && <span className="text-red-500 ml-1">*</span>}
                    </label>
                )}
            </div>
        );
    }
);
Checkbox.displayName = "Checkbox";
