import React from 'react';
import { BaseSelect } from './BaseSelect';
import { SelectOption } from '@/components/form-engine/types';

interface MultiSelectProps {
    label?: string;
    error?: string;
    description?: string;
    options: SelectOption[];
    value?: string[];
    onValueChange?: (value: string[]) => void;
    onSearchChange?: (query: string) => void;
    loading?: boolean;
    disabled?: boolean;
    required?: boolean;
    placeholder?: string;
    searchable?: boolean;
    canClear?: boolean;
    className?: string;
    name?: string;

    // Advanced Props
    strictSearch?: boolean;
    trackBy?: string;
    allowNewOption?: boolean;
    appendNewOption?: boolean;
    addOn?: string[];
    canDeselect?: boolean;
    closeOnSelect?: boolean;
    displayCaret?: boolean;
    truncate?: boolean;
    openDirection?: 'top' | 'bottom';
    optionLimit?: number;
    inputType?: string;
    autoComplete?: string;
}

export const MultiSelect: React.FC<MultiSelectProps> = ({
    value,
    onValueChange,
    ...props
}) => {
    return (
        <BaseSelect
            {...props}
            multiple={true}
            value={value}
            onChange={(val) => onValueChange?.(val as string[])}
        />
    );
};
