import { registerElement } from './registry';
import { TextRenderer } from './text/TextRenderer';
import { TextCanvas } from './text/TextCanvas';
import { TextProperties } from './text/TextProperties';
import { TextAreaRenderer } from './textarea/TextAreaRenderer';
import { TextAreaCanvas } from './textarea/TextAreaCanvas';
import { TextAreaProperties } from './textarea/TextAreaProperties';
import { CheckboxRenderer } from './checkbox/CheckboxRenderer';
import { CheckboxCanvas } from './checkbox/CheckboxCanvas';
import { CheckboxProperties } from './checkbox/CheckboxProperties';
import { ToggleRenderer } from './toggle/ToggleRenderer';
import { ToggleCanvas } from './toggle/ToggleCanvas';
import { ToggleProperties } from './toggle/ToggleProperties';
import { RadioRenderer } from './radio/RadioRenderer';
import { RadioCanvas } from './radio/RadioCanvas';
import { RadioProperties } from './radio/RadioProperties';
import { SelectRenderer } from './select/SelectRenderer';
import { SelectCanvas } from './select/SelectCanvas';
import { SelectProperties } from './select/SelectProperties';
import { PhoneRenderer } from './phone/PhoneRenderer';
import { PhoneCanvas } from './phone/PhoneCanvas';
import { PhoneProperties } from './phone/PhoneProperties';
import { AdvancedRenderer } from './advanced/AdvancedRenderer';
import { AdvancedCanvas } from './advanced/AdvancedCanvas';
import { AdvancedProperties } from './advanced/AdvancedProperties';
import { MatrixRenderer } from './matrix/MatrixRenderer';
import { MatrixCanvas } from './matrix/MatrixCanvas';
import { MatrixProperties } from './matrix/MatrixProperties';
import { DateTimeRenderer } from './date-time/DateTimeRenderer';
import { DateTimeCanvas } from './date-time/DateTimeCanvas';
import { DateTimeProperties } from './date-time/DateTimeProperties';
import { FileRenderer } from './file/FileRenderer';
import { FileCanvas } from './file/FileCanvas';
import { FileProperties } from './file/FileProperties';
import { SlidersRenderer } from './sliders/SlidersRenderer';
import { SlidersCanvas } from './sliders/SlidersCanvas';
import { SlidersProperties } from './sliders/SlidersProperties';
import { StaticRenderer } from './static/StaticRenderer';
import { StaticCanvas } from './static/StaticCanvas';
import { StaticProperties } from './static/StaticProperties';
import { ButtonRenderer } from './button/ButtonRenderer';
import { ButtonCanvas } from './button/ButtonCanvas';
import { ButtonProperties } from './button/ButtonProperties';
import { ContainerRenderer } from './layout/ContainerRenderer';
import { BannerRenderer } from './layout/BannerRenderer';

// Register Text-based elements
const textTypes = ['text', 'email', 'url', 'password', 'number', 'location', 'hidden'] as const;

textTypes.forEach(type => {
    registerElement({
        type: type as any,
        renderer: TextRenderer as any,
        canvas: TextCanvas as any,
        properties: TextProperties as any
    });
});

registerElement({
    type: 'textarea',
    renderer: TextAreaRenderer as any,
    canvas: TextAreaCanvas as any,
    properties: TextAreaProperties as any
});

registerElement({
    type: 'checkbox',
    renderer: CheckboxRenderer as any,
    canvas: CheckboxCanvas as any,
    properties: CheckboxProperties as any
});

const checkboxGroupTypes = ['checkbox-group', 'checkbox-blocks', 'checkbox-tabs'] as const;
checkboxGroupTypes.forEach(type => {
    registerElement({
        type: type as any,
        renderer: SelectRenderer as any,
        canvas: CheckboxCanvas as any,
        properties: CheckboxProperties as any
    });
});

registerElement({
    type: 'toggle',
    renderer: ToggleRenderer as any,
    canvas: ToggleCanvas as any,
    properties: ToggleProperties as any
});

const radioTypes = ['radio', 'radio-group', 'radio-blocks', 'radio-tabs'] as const;
radioTypes.forEach(type => {
    registerElement({
        type: type as any,
        renderer: RadioRenderer as any,
        canvas: RadioCanvas as any,
        properties: RadioProperties as any
    });
});

const selectTypes = ['select', 'multiselect', 'tags', 'top-of-mind'] as const;
selectTypes.forEach(type => {
    registerElement({
        type: type as any,
        renderer: SelectRenderer as any,
        canvas: SelectCanvas as any,
        properties: SelectProperties as any
    });
});

registerElement({
    type: 'phone',
    renderer: PhoneRenderer as any,
    canvas: PhoneCanvas as any,
    properties: PhoneProperties as any
});

const advancedTypes = ['wysiwyg', 'signature', 'captcha'] as const;
advancedTypes.forEach(type => {
    registerElement({
        type: type as any,
        renderer: AdvancedRenderer as any,
        canvas: AdvancedCanvas as any,
        properties: AdvancedProperties as any
    });
});

const matrixTypes = ['matrix', 'matrix-table'] as const;
matrixTypes.forEach(type => {
    registerElement({
        type: type as any,
        renderer: MatrixRenderer as any,
        canvas: MatrixCanvas as any,
        properties: MatrixProperties as any
    });
});

const dateTimeTypes = ['date', 'datetime', 'multiple-dates', 'date-range', 'time'] as const;
dateTimeTypes.forEach(type => {
    registerElement({
        type: type as any,
        renderer: DateTimeRenderer as any,
        canvas: DateTimeCanvas as any,
        properties: DateTimeProperties as any
    });
});

const fileTypes = ['file-upload', 'multi-file-upload', 'image-upload', 'multi-image-upload', 'gallery'] as const;
fileTypes.forEach(type => {
    registerElement({
        type: type as any,
        renderer: FileRenderer as any,
        canvas: FileCanvas as any,
        properties: FileProperties as any
    });
});

const sliderTypes = ['slider', 'range-slider', 'vertical-slider'] as const;
sliderTypes.forEach(type => {
    registerElement({
        type: type as any,
        renderer: SlidersRenderer as any,
        canvas: SlidersCanvas as any,
        properties: SlidersProperties as any
    });
});

const staticTypes = ['h1', 'h2', 'h3', 'h4', 'p', 'quote', 'link', 'image', 'static-html', 'divider'] as const;
staticTypes.forEach(type => {
    registerElement({
        type: type as any,
        renderer: StaticRenderer as any,
        canvas: StaticCanvas as any,
        properties: StaticProperties as any
    });
});

const buttonTypes = ['button', 'submit-button', 'reset-button', 'primary-button', 'secondary-button', 'danger-button'] as const;
buttonTypes.forEach(type => {
    registerElement({
        type: type as any,
        renderer: ButtonRenderer as any,
        canvas: ButtonCanvas as any,
        properties: ButtonProperties as any
    });
});

const layoutTypes = ['container', 'two-columns', 'three-columns', 'four-columns', 'grid'] as const;
layoutTypes.forEach(type => {
    registerElement({
        type: type as any,
        renderer: ContainerRenderer as any,
        canvas: null as any, // Structural elements keep original canvas for now due to drag-drop logic
        properties: null as any
    });
});

registerElement({
    type: 'banner',
    renderer: BannerRenderer as any,
    canvas: null as any,
    properties: null as any
});