import React from 'react';
import { FormElement } from '../../types';

interface TextCanvasProps {
    element: FormElement;
    isSelected: boolean;
}

export const TextCanvas: React.FC<TextCanvasProps> = ({ element, isSelected }) => {
    // Determine height based on 'size' prop
    let heightClass = "h-10";
    let textClass = "text-sm";
    if (element.size === 'sm') { heightClass = "h-8"; textClass = "text-xs"; }
    else if (element.size === 'lg') { heightClass = "h-12"; textClass = "text-base"; }

    const commonInputBaseClass = `w-full ${heightClass} bg-transparent ${textClass} focus:outline-none ${element.disabled ? 'text-slate-400 cursor-not-allowed' : 'text-slate-900'}`;
    const inputWrapperClass = `flex items-center w-full rounded-md border bg-white px-3 transition-all ${isSelected ? 'border-primary' : 'border-slate-300'} ${element.disabled ? 'bg-slate-100' : ''}`;

    return (
        <div className={inputWrapperClass}>
            {element.prefix && <span className="text-slate-400 mr-2 shrink-0 flex items-center" dangerouslySetInnerHTML={{ __html: element.prefix }} />}
            <input
                type={(element.type === 'location' ? 'text' : element.type) as any}
                placeholder={element.placeholder}
                disabled={element.disabled}
                readOnly={element.readOnly}
                defaultValue={element.defaultValue as any}
                className={commonInputBaseClass}
            />
            {element.suffix && <span className="text-slate-400 ml-2 shrink-0 flex items-center" dangerouslySetInnerHTML={{ __html: element.suffix }} />}
        </div>
    );
};
