
import React, { useState } from 'react';
import { FormElement } from '../../form-engine/types';
import { UseFormRegisterReturn, UseFormSetValue } from 'react-hook-form';
import { Upload, X, File as FileIcon, Loader2 } from 'lucide-react';

interface FileUploadProps {
    element: FormElement;
    register: UseFormRegisterReturn;
    setValue: UseFormSetValue<any>;
    error?: string;
    onUpload?: (file: File) => Promise<string>;
    value?: string | string[]; // URL or Array of URLs
    hideLabel?: boolean;
}

export const FileUpload: React.FC<FileUploadProps> = ({
    element,
    register,
    setValue,
    error,
    onUpload,
    value,
    hideLabel
}) => {
    const [isUploading, setIsUploading] = useState(false);
    const [preview, setPreview] = useState<string | null>(typeof value === 'string' ? value : null);
    const [isFocused, setIsFocused] = useState(false);

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        // Basic validation
        if (element.fileMaxSize && file.size > element.fileMaxSize * 1024 * 1024) {
            alert(`File too large. Max size is ${element.fileMaxSize}MB`);
            return;
        }

        // Set preview for images
        if (file.type.startsWith('image/')) {
            const reader = new FileReader();
            reader.onload = (e) => setPreview(e.target?.result as string);
            reader.readAsDataURL(file);
        } else {
            setPreview(null);
        }

        if (onUpload) {
            setIsUploading(true);
            try {
                const url = await onUpload(file);
                // Set the URL as the value in the form, not the File object
                setValue(element.name || '', url, { shouldValidate: true });
            } catch (err) {
                console.error('Upload failed', err);
                alert('Upload failed. Please try again.');
            } finally {
                setIsUploading(false);
            }
        } else {
            // Fallback: Store the File object directly (standard HTML behavior)
            // We need to re-register it essentially or just let the input handle it, 
            // but since we controlled the input onChange, we need to manually set it?
            // Actually, for React Hook Form "register", we can just pass the event if we didn't override onChange entirely.
            // But since we want to support "intercepting" the upload, we manually setValue.

            // NOTE: Storing the File object might not be what the JSON payload expects (it expects a string).
            // But if onUpload is missing, we can't get a URL.
            // We'll leave it as is (File object) and the submit handler will have to deal with it (e.g. FormData).
            setValue(element.name || '', file, { shouldValidate: true });
        }
    };

    const handleRemove = () => {
        setValue(element.name || '', '', { shouldValidate: true });
        setPreview(null);
    };

    return (
        <div className="w-full">
            {!hideLabel && (
                <label className="text-sm font-medium mb-1.5 block text-slate-700">
                    {element.label}
                    {element.required && <span className="text-red-500 ml-1">*</span>}
                </label>
            )}

            {!value && !preview ? (
                <div className="relative">
                    <input
                        type="file"
                        id={element.id}
                        disabled={isUploading || element.disabled}
                        className="hidden"
                        onChange={handleFileChange}
                        onFocus={() => setIsFocused(true)}
                        onBlur={() => setIsFocused(false)}
                        accept={element.fileAcceptTypes?.join(',') || element.fileExtensions?.map(e => `.${e}`).join(',')}
                    />
                    <label
                        htmlFor={element.id}
                        className={`flex flex-col items-center justify-center w-full h-32 border-2 border-dashed rounded-lg cursor-pointer bg-slate-50 hover:bg-slate-100 transition-all ${error ? 'border-red-300' : isFocused ? 'border-primary bg-primary/5' : 'border-slate-300'}`}
                    >
                        {isUploading ? (
                            <div className="flex flex-col items-center gap-2">
                                <Loader2 className="h-8 w-8 animate-spin text-primary" />
                                <span className="text-sm text-slate-500">Uploading...</span>
                            </div>
                        ) : (
                            <div className="flex flex-col items-center pt-5 pb-6 gap-2">
                                <Upload className="w-8 h-8 text-slate-400" />
                                <p className="text-sm text-slate-500">
                                    <span className="font-semibold">Click to upload</span> or drag and drop
                                </p>
                                <p className="text-xs text-slate-400">
                                    {element.fileAcceptTypes ? element.fileAcceptTypes.join(', ') : 'Any file'}
                                </p>
                            </div>
                        )}
                    </label>
                </div>
            ) : (
                <div className="relative flex items-center p-3 border border-slate-200 rounded-lg bg-slate-50">
                    <div className="flex-shrink-0 mr-3">
                        {preview ? (
                            <img src={preview} alt="Preview" className="h-10 w-10 object-cover rounded" />
                        ) : (
                            <div className="h-10 w-10 bg-slate-200 rounded flex items-center justify-center">
                                <FileIcon className="h-5 w-5 text-slate-500" />
                            </div>
                        )}
                    </div>
                    <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium text-slate-900 truncate">
                            {value instanceof File ? value.name : 'Uploaded File'}
                        </p>
                        <p className="text-xs text-slate-500 truncate">
                            {value instanceof File ? Math.round(value.size / 1024) + ' KB' : 'Ready'}
                        </p>
                    </div>
                    <button
                        type="button"
                        onClick={handleRemove}
                        className="ml-2 inline-flex items-center justify-center h-8 w-8 rounded-full text-slate-400 hover:text-red-500 hover:bg-red-50 transition-colors"
                    >
                        <X className="w-4 h-4" />
                    </button>
                </div>
            )}

            {error && <p className="text-xs text-red-500 mt-1">{error}</p>}
        </div>
    );
};
