import React from 'react';
import { FormElement } from '../../types';
import { FileUpload } from '../../../ui/fields/FileUpload';
import { useFormContext } from 'react-hook-form';

interface FileRendererProps {
    element: FormElement;
    prefix?: string;
    onUpload?: (file: File) => Promise<string>;
}

export const FileRenderer: React.FC<FileRendererProps> = ({
    element,
    prefix = '',
    onUpload
}) => {
    const { watch, setValue, register, formState: { errors } } = useFormContext();
    const fieldName = prefix
        ? `${prefix}${element.name ? `.${element.name}` : ''}`
        : element.name || `element_${element.id.replace(/-/g, '_')}`;

    const error = errors[fieldName]?.message as string | undefined;
    const value = watch(fieldName);

    return (
        <FileUpload
            key={element.id}
            element={element}
            register={element.name ? register(fieldName) : undefined as any}
            setValue={setValue}
            error={error}
            onUpload={onUpload}
            value={value}
            hideLabel={true}
        />
    );
};
