'use client';

import React from 'react';
import { useForm, FormProvider } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { FormElement, WelcomePageConfig, ThankYouPageConfig } from '../types';
import { Input } from '@/components/ui/fields/Input';
import { TextArea } from '@/components/ui/fields/TextArea';
import { Select } from '@/components/ui/fields/Select';
import { Checkbox } from '@/components/ui/fields/Checkbox';
import { RadioGroup } from '@/components/ui/fields/RadioGroup';
import { DatePicker } from '@/components/ui/fields/DatePicker';
import { Switch } from '@/components/ui/fields/Switch';
import { CheckboxGroup } from '@/components/ui/fields/CheckboxGroup';
import { Slider } from '@/components/ui/fields/Slider';
import { RangeSlider } from '@/components/ui/fields/RangeSlider';
import { MultiSelect } from '@/components/ui/fields/MultiSelect';
import { Matrix } from '@/components/ui/fields/Matrix';
import { PhoneInput } from '@/components/ui/fields/PhoneInput';
import { RichTextEditor } from '@/components/ui/fields/RichTextEditor';
import { Info } from 'lucide-react';
import { evaluateConditionGroup, getResponsiveSpanClasses } from '../core/utils';
import { evaluateFormExpression } from '../core/expressions';
import { ThemeProvider } from './ThemeProvider';
import { SmartFieldRenderer } from './SmartFieldRenderer';
import { FileUpload } from '@/components/ui/fields/FileUpload';
import { TopOfMindField } from '@/components/ui/fields/TopOfMindField';
import { WelcomeScreen } from './WelcomeScreen';
import { ThankYouScreen } from './ThankYouScreen';
import { AnimatePresence, motion } from 'framer-motion';
import { DEVICE_WIDTHS } from '../core/constants';
import { DeviceType } from '../types';
import { getElement } from '../elements/registry';
import '../elements'; // Trigger element registration
import { FieldWrapper } from '../elements/common/FieldWrapper';

// Form State Machine
export enum FormState {
    WELCOME = 'welcome',
    FORM = 'form',
    THANK_YOU = 'thank_you'
}

interface FormRendererProps {
    elements: FormElement[];
    onSubmit: (data: any) => void;
    isSubmitting?: boolean;
    config?: any;
    themeConfig?: any; // Theme Configuration
    customFunctions?: Record<string, Function>;
    onUpload?: (file: File) => Promise<string>;
    onChange?: (values: any) => void;
    initialValues?: any;
    initialStepIndex?: number;
    onStepChange?: (index: number) => void;
    welcomePage?: WelcomePageConfig;
    thankYouPage?: ThankYouPageConfig;
    viewDevice?: DeviceType;
    startState?: 'welcome' | 'form' | 'thank_you';
}



// Helper: Normalize elements to always be an array
function normalizeElements(elements: any): FormElement[] {
    if (Array.isArray(elements)) return elements;
    if (elements && typeof elements === 'object' && Array.isArray(elements.elements)) {
        return elements.elements;
    }
    return [];
}

// Helper: Generate Zod schema from FormElements
function generateZodSchema(elements: FormElement[], values: any = {}) {
    const safeElements = normalizeElements(elements);
    const shape: Record<string, z.ZodTypeAny> = {};

    const processElements = (items: FormElement[]) => {
        if (!Array.isArray(items)) return;
        items.forEach((el) => {
            const shouldSubmit = el.name && (el.submitData !== false);
            if (shouldSubmit) {
                // Check visibility - if hidden, we make it optional/any to avoid validation errors on hidden fields
                let isVisible = true;
                if (el.visibilityExpression) {
                    try {
                        const expr = el.visibilityExpression.replace(/\{(\w+)\}/g, (_, name) => {
                            const val = values[name];
                            return typeof val === 'string' ? `'${val}'` : val;
                        });
                        isVisible = eval(expr);
                    } catch (e) { isVisible = true; }
                } else if (el.visibilityConditions) {
                    isVisible = evaluateConditionGroup(el.visibilityConditions, values);
                }

                if (!isVisible || !el.name) {
                    if (el.name) {
                        shape[el.name] = z.any().optional();
                    }
                } else {
                    let fieldSchema: z.ZodTypeAny = z.string();

                    // Type-specific schemas
                    switch (el.type) {
                        case 'text':
                        case 'location':
                        case 'textarea':
                            fieldSchema = z.string();
                            if (el.minLength !== undefined) {
                                fieldSchema = (fieldSchema as z.ZodString).min(el.minLength, `The ${el.label || 'field'} must be at least ${el.minLength} characters.`);
                            }
                            if (el.maxLength !== undefined) {
                                fieldSchema = (fieldSchema as z.ZodString).max(el.maxLength, `The ${el.label || 'field'} may not be greater than ${el.maxLength} characters.`);
                            }
                            if (el.exactLength !== undefined) {
                                fieldSchema = (fieldSchema as z.ZodString).length(el.exactLength, `The ${el.label || 'field'} must be exactly ${el.exactLength} characters.`);
                            }
                            if (el.regex) {
                                try {
                                    let regexStr = el.regex;
                                    let flags = '';
                                    const match = el.regex.match(/^\/(.*)\/([gimsuy]*)$/);
                                    if (match) {
                                        regexStr = match[1];
                                        flags = match[2];
                                    }
                                    const regex = new RegExp(regexStr, flags);

                                    if (el.patternMatchMode === 'not-match') {
                                        fieldSchema = (fieldSchema as z.ZodString).refine(val => !val || !regex.test(val), `The ${el.label || 'field'} format is invalid.`);
                                    } else {
                                        fieldSchema = (fieldSchema as z.ZodString).refine(val => !val || regex.test(val), `The ${el.label || 'field'} format is invalid.`);
                                    }
                                } catch (e) {
                                    console.error('Invalid regex:', el.regex);
                                }
                            }
                            break;
                        case 'email':
                            fieldSchema = z.string().email('Email inválido');
                            break;
                        case 'url':
                            fieldSchema = z.string().url('URL inválida');
                            break;
                        case 'phone':
                            fieldSchema = z.string().min(8, 'Telefone inválido');
                            break;
                        case 'number':
                            fieldSchema = z.coerce.number();
                            if (el.min !== undefined || el.minValue !== undefined) {
                                const minVal = el.min ?? el.minValue;
                                fieldSchema = (fieldSchema as z.ZodNumber).min(minVal!, `The ${el.label || 'field'} must be at least ${minVal}.`);
                            }
                            if (el.max !== undefined || el.maxValue !== undefined) {
                                const maxVal = el.max ?? el.maxValue;
                                fieldSchema = (fieldSchema as z.ZodNumber).max(maxVal!, `The ${el.label || 'field'} may not be greater than ${maxVal}.`);
                            }
                            break;
                        case 'checkbox':
                        case 'toggle':
                            fieldSchema = z.boolean();
                            break;
                        case 'checkbox-group':
                        case 'checkbox-blocks':
                        case 'checkbox-tabs':
                            fieldSchema = z.array(z.string());
                            break;
                        case 'date':
                        case 'time':
                        case 'datetime':
                            fieldSchema = z.string();
                            break;
                        case 'multiple-dates':
                            fieldSchema = z.array(z.string());
                            break;
                        case 'date-range':
                            fieldSchema = z.array(z.string()).length(2, 'Selecione a data inicial e final');
                            break;
                        case 'slider':
                        case 'vertical-slider':
                            fieldSchema = z.coerce.number();
                            if (el.min !== undefined) fieldSchema = (fieldSchema as z.ZodNumber).min(el.min);
                            if (el.max !== undefined) fieldSchema = (fieldSchema as z.ZodNumber).max(el.max);
                            break;
                        case 'range-slider':
                            fieldSchema = z.array(z.coerce.number()).min(1);
                            break;
                        case 'select':
                        case 'multiselect':
                        case 'top-of-mind':
                        case 'tags':
                            if (el.useObjectValue) {
                                fieldSchema = (el.type === 'multiselect' || el.type === 'tags') ? z.array(z.any()) : z.any();
                            } else {
                                fieldSchema = (el.type === 'multiselect' || el.type === 'tags') ? z.array(z.string()) : z.string();
                            }
                            break;
                        case 'file-upload':
                        case 'image-upload':
                            fieldSchema = z.any();
                            break;
                        case 'matrix':
                        case 'matrix-table':
                            fieldSchema = z.record(z.string(), z.string());
                            break;
                        default:
                            fieldSchema = z.string();
                    }

                    // Apply required
                    let isRequired = el.required === true;
                    const hasReqConditions = (el.requiredConditions?.conditions?.length || 0) > 0 || !!el.requiredExpression;

                    if (isRequired && hasReqConditions) {
                        if (el.requiredExpression) {
                            try {
                                const expr = el.requiredExpression.replace(/\{(\w+)\}/g, (_, name) => {
                                    const val = values[name];
                                    return typeof val === 'string' ? `'${val}'` : val;
                                });
                                isRequired = eval(expr);
                            } catch (e) { isRequired = false; }
                        } else if (el.requiredConditions) {
                            isRequired = evaluateConditionGroup(el.requiredConditions, values);
                        }
                    }

                    if (isRequired) {
                        if (el.type === 'checkbox' || el.type === 'toggle') {
                            fieldSchema = (fieldSchema as z.ZodBoolean).refine((val) => val === true, {
                                message: 'Este campo é obrigatório'
                            });
                        } else if (el.type === 'checkbox-group' || el.type === 'multiselect' || el.type === 'tags') {
                            fieldSchema = (fieldSchema as z.ZodArray<any>).min(1, 'Selecione pelo menos uma opção');
                        } else if (el.type === 'file-upload' || el.type === 'image-upload') {
                            fieldSchema = (fieldSchema as z.ZodAny).refine((val) => !!val && (val instanceof FileList ? val.length > 0 : !!val), 'Arquivo obrigatório');
                        } else if (el.type === 'text' || el.type === 'textarea' || el.type === 'email' || el.type === 'url') {
                            fieldSchema = (fieldSchema as z.ZodString).min(1, 'Este campo é obrigatório');
                        }
                    } else {
                        if (el.type === 'text' || el.type === 'textarea' || el.type === 'email' || el.type === 'url') {
                            fieldSchema = z.preprocess((val) => val === '' ? undefined : val, fieldSchema.optional());
                        } else {
                            fieldSchema = fieldSchema.optional();
                        }
                    }

                    if (el.name) {
                        shape[el.name] = fieldSchema;
                    }
                }
            }

            // Recursive call for children
            if (el.children && el.children.length > 0) {
                processElements(el.children);
            }
        });
    }

    processElements(safeElements);
    return z.object(shape);
}

export const FormRenderer: React.FC<FormRendererProps> = ({
    elements,
    onSubmit,
    isSubmitting = false,
    config,
    themeConfig,
    customFunctions = {},
    onUpload,
    onChange,
    initialValues,
    initialStepIndex = 0,
    onStepChange,
    welcomePage,
    thankYouPage,
    viewDevice,
    startState
}) => {

    // State Machine: Determine initial state
    const getInitialFormState = (): FormState => {
        if (welcomePage?.enabled) {
            return FormState.WELCOME;
        }
        return FormState.FORM;
    };

    const [currentFormState, setCurrentFormState] = React.useState<FormState>(getInitialFormState());

    // Allow external control of the state (useful for preview)
    React.useEffect(() => {
        if (startState) {
            setCurrentFormState(startState as FormState);
        }
    }, [startState]);

    const [isFormSubmitted, setIsFormSubmitted] = React.useState(false);

    const safeElements = React.useMemo(() => normalizeElements(elements), [elements]);
    const [activeStepIndex, setActiveStepIndex] = React.useState(initialStepIndex);

    // Sync external initialStepIndex if it changes
    React.useEffect(() => {
        if (initialStepIndex !== undefined) {
            setActiveStepIndex(initialStepIndex);
        }
    }, [initialStepIndex]);

    // Internal handler to notify parent
    const handleStepChange = (index: number) => {
        setActiveStepIndex(index);
        onStepChange?.(index);
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };
    const [activeTabs, setActiveTabs] = React.useState<Record<string, number>>({});
    const resolver = React.useCallback(
        async (data: any, context: any, options: any) => {
            const dynamicSchema = generateZodSchema(safeElements, data);
            return zodResolver(dynamicSchema)(data, context, options);
        },
        [safeElements]
    );

    const [listCounts, setListCounts] = React.useState<Record<string, number>>(() => {
        const counts: Record<string, number> = {};
        const process = (items: FormElement[]) => {
            if (!Array.isArray(items)) return;
            items.forEach(el => {
                if (el.type === 'list') {
                    counts[el.id] = el.initialInstances || 1;
                }
                if (el.children) process(el.children);
            });
        };
        process(safeElements);
        return counts;
    });

    const methods = useForm({
        resolver,
        defaultValues: React.useMemo(() => {
            const defaults: Record<string, any> = { ...initialValues };
            const processDefaults = (items: FormElement[]) => {
                if (!Array.isArray(items)) return;
                items.forEach(el => {
                    if (el.name && el.defaultValue !== undefined && defaults[el.name] === undefined) {
                        defaults[el.name] = el.defaultValue;
                    }
                    if (el.children && el.children.length > 0) {
                        processDefaults(el.children);
                    }
                });
            };
            processDefaults(safeElements);
            return defaults;
        }, [safeElements, initialValues]),
        mode: 'onChange'
    });

    const {
        register,
        handleSubmit,
        formState: { errors },
        setValue,
        watch,
        reset,
        trigger,
        getValues
    } = methods;

    // Reset form if initialValues change externally (e.g. on load)
    React.useEffect(() => {
        if (initialValues && Object.keys(initialValues).length > 0) {
            reset(initialValues);
        }
    }, [initialValues, reset]);

    const values = watch();

    // Collect all field names to ensure they are available in the expression scope
    const allFieldNames = React.useMemo(() => {
        const names = new Set<string>();
        const process = (items: FormElement[]) => {
            if (!Array.isArray(items)) return;
            items.forEach(el => {
                if (el.name) names.add(el.name);
                if (el.children) process(el.children);
            });
        };
        process(safeElements);
        return Array.from(names);
    }, [safeElements]);

    // Create a complete values object including all possible fields as null if missing
    const completeValues = React.useMemo(() => {
        const full: Record<string, any> = {};
        allFieldNames.forEach(name => {
            full[name] = values[name] !== undefined ? values[name] : null;
        });
        return { ...full, ...values };
    }, [allFieldNames, values]);

    // Notify parent of changes with loop protection
    const lastNotifiedValues = React.useRef<string>('');
    React.useEffect(() => {
        if (onChange) {
            const stringified = JSON.stringify(values);
            if (stringified !== lastNotifiedValues.current) {
                lastNotifiedValues.current = stringified;
                onChange(values);
            }
        }
    }, [values, onChange]);


    // Parse global scripts into custom functions
    const scriptsFunctions = React.useMemo(() => {
        if (!config?.scripts || !Array.isArray(config.scripts)) return {};

        let allFunctions: Record<string, Function> = {};

        config.scripts.forEach((script: { content: string; active?: boolean; name: string }) => {
            if (!script.content || script.active === false) return;

            try {
                // Wrap in IIFE and return result
                const scriptToRun = script.content.includes('return')
                    ? `(function(){ ${script.content} })()`
                    : `(function(){ ${script.content}; return {}; })()`;

                const fn = new Function('return ' + scriptToRun);
                const result = fn();
                if (typeof result === 'object' && result !== null) {
                    allFunctions = { ...allFunctions, ...result };
                }
            } catch (e) {
                console.error(`Error in global script "${script.name}":`, e);
            }
        });

        return allFunctions;
    }, [config?.scripts]);

    const allCustomFunctions = React.useMemo(() => ({ ...scriptsFunctions, ...customFunctions }), [scriptsFunctions, customFunctions]);

    // Handle Expression Evaluations
    React.useEffect(() => {
        const processExpressions = (items: FormElement[]) => {
            if (!Array.isArray(items)) return;
            items.forEach(el => {
                if (el.name && el.useExpressionValue && el.expression) {
                    const result = evaluateFormExpression(el.expression, completeValues, allCustomFunctions);
                    const currentValue = getValues(el.name);
                    if (result !== String(currentValue)) {
                        setValue(el.name, result);
                    }
                }
                if (el.children) processExpressions(el.children);
            });
        };
        processExpressions(safeElements);
    }, [completeValues, safeElements, allCustomFunctions, setValue, getValues]);

    const hasSubmitButton = React.useMemo(() => {
        const check = (items: FormElement[]): boolean => {
            if (!Array.isArray(items)) return false;
            return items.some(el =>
                (el.type === 'submit-button' || el.type === 'primary-button') ||
                (el.children && el.children.length > 0 && check(el.children))
            );
        };
        return check(elements);
    }, [elements]);

    const isVisible = (element: FormElement) => {
        if (element.visibilityExpression) {
            try {
                // VERY BASIC expression evaluator for MVP. Replace with real sandbox if needed.
                const expr = element.visibilityExpression.replace(/\{(\w+)\}/g, (_, name) => {
                    const val = values[name];
                    return typeof val === 'string' ? `'${val}'` : val;
                });
                return eval(expr);
            } catch (e) {
                return true;
            }
        }
        if (element.visibilityConditions) {
            return evaluateConditionGroup(element.visibilityConditions, values);
        }
        return true;
    };

    const isElementRequired = (element: FormElement) => {
        // If the base required toggle is off, it's never required (this matches UI behavior where conditions are hidden when toggle is off)
        if (!element.required) return false;

        const hasConditions = (element.requiredConditions?.conditions?.length || 0) > 0 || !!element.requiredExpression;

        // If the toggle is on but no specific conditions are set, it's always required
        if (!hasConditions) return true;

        // If conditions are set, they determine the required state
        if (element.requiredExpression) {
            try {
                const expr = element.requiredExpression.replace(/\{(\w+)\}/g, (_, name) => {
                    const val = values[name];
                    return typeof val === 'string' ? `'${val}'` : val;
                });
                return eval(expr);
            } catch (e) {
                return false;
            }
        }
        if (element.requiredConditions) {
            return evaluateConditionGroup(element.requiredConditions, values);
        }

        return false;
    };

    const renderRecursiveElement = (element: FormElement, parentIndex?: number, prefixForName: string = '', parentDirection?: string): React.ReactNode => {
        if (!isVisible(element)) return null;

        const fieldName = prefixForName
            ? `${prefixForName}${element.name ? `.${element.name}` : ''}`
            : element.name || `element_${element.id.replace(/-/g, '_')}`;
        const error = errors[fieldName]?.message as string | undefined;

        const isParentColumn = parentDirection === 'column';

        // Responsive Spans - Force 12 if parent is strictly a column
        const mobileSpan = (element.fullWidth || isParentColumn) ? 12 : (element.mobileColSpan || 12);
        const tabletSpan = (element.fullWidth || isParentColumn) ? 12 : (element.tabletColSpan || 12);
        const desktopSpan = (element.fullWidth || isParentColumn) ? 12 : (element.colSpan || 12);

        const spanClasses = getResponsiveSpanClasses(mobileSpan, tabletSpan, desktopSpan);

        const alignment = element.align || 'left';
        const justifyClass = alignment === 'center' ? 'flex justify-center' : alignment === 'right' ? 'flex justify-end' : '';

        const isStatic = ['h1', 'h2', 'h3', 'h4', 'p', 'quote', 'link', 'divider', 'image', 'static-html', 'banner'].includes(element.type);
        const isButton = element.type.includes('button');
        const isHeaderOnly = ['step', 'tab'].includes(element.type);
        const hideLabel = isButton || isStatic || isHeaderOnly;

        // Função para verificar se o campo tem valor (suporta strings, arrays e objetos)
        const getFieldValue = (path: string): any => {
            if (!path) return undefined;
            return path.split('.').reduce((obj, key) => (obj && typeof obj === 'object') ? obj[key] : undefined, values);
        };
        const currentVal = getFieldValue(fieldName);

        // Verifica se está preenchido (não é null, undefined, string vazia, array vazio ou objeto vazio)
        const isFilled = (() => {
            if (currentVal === undefined || currentVal === null) return false;
            if (typeof currentVal === 'boolean') return true;
            if (typeof currentVal === 'string') return currentVal.trim() !== '';
            if (Array.isArray(currentVal)) return currentVal.length > 0;
            if (typeof File !== 'undefined' && currentVal instanceof File) return true;
            if (typeof FileList !== 'undefined' && currentVal instanceof FileList) return currentVal.length > 0;
            if (typeof currentVal === 'object') return Object.keys(currentVal).length > 0;
            return true;
        })();

        return (
            <div
                key={element.id}
                className={`${spanClasses} ${justifyClass}`}
            >
                <div className={element.fullWidth ? 'w-full' : 'w-full'}>
                    {/* Render Label */}
                    {!hideLabel && (
                        <div className="flex items-center gap-2 mb-1.5 flex-wrap">
                            <label className="block text-xs font-semibold text-slate-700">
                                {element.label}
                            </label>
                            {isElementRequired(element) && (
                                <span className={`text-[8px] font-bold px-1.5 py-0.5 rounded uppercase tracking-wider border transition-all duration-300 ${isFilled
                                    ? "bg-emerald-100 text-emerald-600 border-emerald-200"
                                    : "bg-red-100 text-red-600 border-red-200"
                                    }`}>
                                    {isFilled ? 'Preenchido' : 'Obrigatório'}
                                </span>
                            )}
                            {element.tooltip && (
                                <div className="group relative ml-0.5">
                                    <Info size={12} className="text-slate-400 cursor-help" />
                                    <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-max max-w-[200px] px-2.5 py-1.5 bg-slate-900 text-white text-[10px] rounded shadow-lg opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-50 whitespace-normal text-center">
                                        {element.tooltip}
                                    </div>
                                </div>
                            )}
                        </div>
                    )}

                    {/* Before Decorator */}
                    {element.before && <div className="text-[10px] text-slate-400 mb-1" dangerouslySetInnerHTML={{ __html: element.before }} />}

                    {/* Main Field Content */}
                    {renderField(element, prefixForName)}

                    {/* Error message */}
                    {error && <p className="text-[10px] text-red-500 mt-1">{error}</p>}

                    {/* Between Decorator */}
                    {element.between && <div className="text-[10px] text-slate-400 mt-2 mb-1" dangerouslySetInnerHTML={{ __html: element.between }} />}

                    {/* Description */}
                    {!hideLabel && element.description && (
                        <p className="mt-1 text-[10px] text-slate-500">{element.description}</p>
                    )}

                    {/* After Decorator */}
                    {element.after && <div className="text-[10px] text-slate-500 mt-1" dangerouslySetInnerHTML={{ __html: element.after }} />}
                </div>
            </div>
        );
    };

    const renderField = (element: FormElement, prefixForName: string = '') => {
        const isStatic = ['h1', 'h2', 'h3', 'h4', 'p', 'quote', 'link', 'divider', 'image', 'static-html'].includes(element.type);
        const isButton = element.type.includes('button');
        const isStructure = ['tabs', 'steps', 'grid', 'container', 'two-columns', 'three-columns', 'four-columns', 'layout-table', 'repeater-list', 'nested-list'].includes(element.type);

        // Fields that submit data MUST have a name
        if (!isStatic && !isButton && !isStructure && !element.name) return null;

        const fieldName = prefixForName
            ? `${prefixForName}${element.name ? `.${element.name}` : ''}`
            : element.name || `element_${element.id.replace(/-/g, '_')}`;
        const error = errors[fieldName]?.message as string | undefined;

        // Global layout overrides
        const globalSize = config?.layout?.size || 'md';
        const globalFloat = config?.layout?.floatPlaceholders ? 'on' : 'default';

        const commonProps = {
            error,
            required: isElementRequired(element),
            disabled: element.disabled || element.readOnly,
            placeholder: element.placeholder,
            prefix: element.prefix,
            suffix: element.suffix,
            mask: element.mask,
            size: element.size || globalSize,
            autoFloat: element.autoFloat || globalFloat,
            min: element.min ?? element.minValue,
            max: element.max ?? element.maxValue,
            step: element.step || element.sliderStep,
        };

        // Limpeza centralizada para evitar avisos no DOM
        const {
            autoFloat,
            submitData,
            view,
            elementId,
            canClear,
            canDeselect,
            truncate,
            ...safeProps
        } = commonProps as any;

        const elementDef = getElement(element.type);
        if (elementDef && elementDef.renderer) {
            const Renderer = elementDef.renderer;
            return (
                <Renderer
                    element={element}
                    register={register}
                    errors={errors}
                    prefix={prefixForName}
                    config={config}
                    renderRecursiveElement={renderRecursiveElement}
                />
            );
        }

        switch (element.type) {
            // --- STRUCTURE ---
            case 'steps':
                const activeStepIdx = activeStepIndex < (element.children?.length || 0) ? activeStepIndex : 0;
                const currentStep = element.children?.[activeStepIdx];
                if (!currentStep) return null;

                const isLastStep = activeStepIdx === (element.children?.length || 0) - 1;
                const showStepsBar = element.showStepsBar !== false;
                const stepsBarMode = element.stepsBarMode || 'full';

                return (
                    <div className="w-full space-y-8">
                        {/* Progress Bar */}
                        {showStepsBar && (
                            <div className="relative flex items-center justify-between px-4 mb-8">
                                {stepsBarMode === 'full' ? (
                                    <>
                                        <div className="absolute left-10 right-10 h-0.5 bg-slate-100 top-4 z-0"></div>
                                        {element.children?.map((step, idx) => (
                                            <div key={step.id} className="relative z-10 flex flex-col items-center gap-2">
                                                <div className={`h-8 w-8 rounded-full flex items-center justify-center text-xs font-bold border-2 transition-all ${idx === activeStepIdx ? 'bg-primary border-primary text-white scale-110 shadow-md' : idx < activeStepIdx ? 'bg-emerald-50 border-primary text-primary' : 'bg-white border-slate-200 text-slate-300'}`}>
                                                    {idx + 1}
                                                </div>
                                                <span className={`text-[10px] font-bold ${idx === activeStepIdx ? 'text-primary' : 'text-slate-400'}`}>{step.label}</span>
                                            </div>
                                        ))}
                                    </>
                                ) : (
                                    <div className="flex flex-col items-center gap-2 w-full">
                                        <div className="h-10 w-10 rounded-full bg-primary border-4 border-emerald-50 text-white flex items-center justify-center text-sm font-bold shadow-sm ring-4 ring-primary/10">
                                            {activeStepIdx + 1}
                                        </div>
                                        <div className="flex flex-col items-center">
                                            <span className="text-[10px] uppercase tracking-widest font-bold text-primary mb-1">Passo Atual</span>
                                            <span className="text-sm font-bold text-slate-700">{currentStep.label}</span>
                                        </div>
                                    </div>
                                )}
                            </div>
                        )}

                        {/* Step Content */}
                        <div className="grid grid-cols-12 gap-x-6 gap-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                            {currentStep.children?.map(el => renderRecursiveElement(el, undefined, prefixForName))}
                        </div>

                        {/* Navigation Buttons */}
                        <div className="flex justify-between items-center pt-6 border-t border-slate-100 mt-8">
                            <div>
                                {currentStep.showPrevious !== false && activeStepIdx > 0 && (
                                    <button
                                        type="button"
                                        onClick={() => {
                                            handleStepChange(Math.max(0, activeStepIdx - 1));
                                        }}
                                        className="px-4 py-2 border rounded text-xs font-bold transition-colors bg-white text-slate-600 border-slate-200 hover:bg-slate-50"
                                    >
                                        {element.previousLabel || 'Anterior'}
                                    </button>
                                )}
                            </div>

                            {!isLastStep ? (
                                currentStep.showNext !== false && (
                                    <button
                                        type="button"
                                        onClick={async (e) => {
                                            e.preventDefault();
                                            e.stopPropagation();
                                            // Validate fields in current step before proceeding
                                            const stepFieldNames: string[] = [];
                                            const collectNames = (items: FormElement[]) => {
                                                items.forEach(child => {
                                                    if (child.name) stepFieldNames.push(child.name);
                                                    if (child.children) collectNames(child.children);
                                                });
                                            };
                                            collectNames(currentStep.children || []);

                                            const isValid = await trigger(stepFieldNames);
                                            if (isValid) {
                                                handleStepChange(activeStepIdx + 1);
                                            }
                                        }}
                                        className="px-6 py-2 bg-primary text-white rounded text-xs font-bold shadow-sm hover:bg-primary/90 transition-all font-mono tracking-wider uppercase"
                                    >
                                        {element.nextLabel || 'Próximo'}
                                    </button>
                                )
                            ) : (
                                currentStep.showNext !== false && !hasSubmitButton && (
                                    <button
                                        type="submit"
                                        className="px-6 py-2.5 bg-emerald-500 text-white rounded-md hover:bg-emerald-600 disabled:opacity-50 disabled:cursor-not-allowed font-bold text-xs shadow-sm transition-colors uppercase tracking-wider"
                                    >
                                        {isSubmitting ? 'Enviando...' : (element.finishLabel || 'Finalizar')}
                                    </button>
                                )
                            )}
                        </div>
                    </div>
                );

            case 'tabs':
                const activeTabIdx = activeTabs[element.id] !== undefined ? activeTabs[element.id] : (element.activeTabIndex || 0);
                return (
                    <div className="w-full space-y-6">
                        <div className="flex border-b border-slate-200 overflow-x-auto no-scrollbar">
                            {element.children?.map((tab, idx) => (
                                <button
                                    key={tab.id}
                                    type="button"
                                    onClick={() => setActiveTabs(prev => ({ ...prev, [element.id]: idx }))}
                                    className={`px-6 py-2.5 text-xs font-bold transition-all border-b-2 whitespace-nowrap uppercase tracking-wider ${activeTabIdx === idx ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}
                                >
                                    {tab.label}
                                </button>
                            ))}
                        </div>
                        <div className="grid grid-cols-12 gap-x-6 gap-y-8 animate-in fade-in duration-500">
                            {element.children?.[activeTabIdx]?.children?.map(el => renderRecursiveElement(el, undefined, prefixForName))}
                        </div>
                    </div>
                );


            case 'layout-table':
                return (
                    <div className="w-full border border-slate-200 rounded-lg overflow-hidden bg-white shadow-sm" key={element.id}>
                        <div className="grid grid-cols-2 bg-slate-50 border-b border-slate-200">
                            <div className="px-4 py-3 text-xs font-bold text-slate-500 uppercase">Col 1</div>
                            <div className="px-4 py-3 text-xs font-bold text-slate-500 uppercase">Col 2</div>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 divide-y md:divide-y-0 md:divide-x divide-slate-100">
                            {element.children?.map(el => renderRecursiveElement(el, undefined, prefixForName))}
                        </div>
                    </div>
                );

            case 'list':

                const count = listCounts[element.id] || 1;
                const canAdd = element.listCanAdd !== false && count < (element.listMax || 10);
                const canRemove = element.listCanRemove !== false && count > (element.listMin || 0);

                return (
                    <div className="w-full space-y-6" key={element.id}>
                        {element.label && (
                            <div className="flex items-center gap-2 mb-2">
                                <label className="text-sm font-bold text-slate-700 uppercase tracking-wider">{element.label}</label>
                            </div>
                        )}

                        <div className="space-y-8">
                            {Array.from({ length: count }).map((_, idx) => (
                                <div key={`${element.id}-${idx}`} className="relative p-6 border border-slate-200 rounded-xl bg-white shadow-sm group">
                                    {canRemove && (
                                        <button
                                            type="button"
                                            onClick={() => setListCounts(prev => ({ ...prev, [element.id]: Math.max(element.listMin || 0, (prev[element.id] || 1) - 1) }))}
                                            className="absolute -top-3 -right-3 h-8 w-8 bg-white border border-slate-200 rounded-full flex items-center justify-center text-slate-400 hover:text-red-500 hover:border-red-200 shadow-sm transition-all z-10 opacity-0 group-hover:opacity-100"
                                        >
                                            <span className="text-lg font-bold">×</span>
                                        </button>
                                    )}
                                    <div className="grid grid-cols-12 gap-x-6 gap-y-4">
                                        {element.children?.map(child => renderRecursiveElement(child, idx, `${prefixForName}${prefixForName ? '.' : ''}${element.name || element.id}.${idx}`))}
                                    </div>
                                </div>
                            ))}
                        </div>

                        {canAdd && (
                            <div className="flex justify-center mt-4">
                                <button
                                    type="button"
                                    onClick={() => setListCounts(prev => ({ ...prev, [element.id]: Math.min(element.listMax || 10, (prev[element.id] || 1) + 1) }))}
                                    className="px-6 py-2.5 bg-white border-2 border-dashed border-slate-200 rounded-xl text-xs font-bold text-slate-500 hover:border-primary hover:text-primary hover:bg-emerald-50/50 transition-all uppercase tracking-widest flex items-center gap-2"
                                >
                                    <span className="text-lg">+</span>
                                    {element.listAddText || 'Adicionar'}
                                </button>
                            </div>
                        )}
                    </div>
                );

            case 'step':
            case 'tab':
                return null; // Handled by parent




            case 'vertical-slider':
                const vSliderValue = element.name ? watch(element.name) : undefined;
                return (
                    <Slider
                        key={element.id}
                        {...commonProps}
                        name={fieldName}
                        min={element.min || element.sliderMin || 0}
                        max={element.max || element.sliderMax || 100}
                        step={element.step || element.sliderStep || 1}
                        value={vSliderValue}
                        orientation="vertical"
                        onValueChange={(val) => element.name && setValue(element.name, val)}
                    />
                );

            case 'multi-file-upload':
            case 'multi-image-upload':
            case 'gallery':
                return (
                    <div className="w-full">
                        <label className="text-sm font-medium mb-1.5 block text-slate-700">
                            {element.label}
                            {element.required && <span className="text-red-500 ml-1">*</span>}
                        </label>
                        <div className="p-4 border-2 border-dashed border-slate-300 rounded-lg bg-slate-50 hover:bg-slate-100 transition-colors text-center cursor-pointer">
                            <input
                                key={element.id}
                                type="file"
                                multiple
                                className="hidden"
                                id={fieldName}
                                {...(element.name ? register(element.name) : {})}
                            />
                            <label htmlFor={fieldName} className="cursor-pointer flex flex-col items-center gap-2">
                                <span className="text-slate-500 text-sm">Clique para upload múltiplos ou arraste aqui</span>
                                <span className="text-xs text-slate-400">(Simulação Visual)</span>
                            </label>
                        </div>
                        {error && <p className="text-xs text-red-500 mt-1">{error}</p>}
                    </div>
                );


            case 'phone':
                const phoneValue = element.name ? watch(element.name) : '';
                return (
                    <PhoneInput
                        key={element.id}
                        {...safeProps}
                        name={fieldName}
                        value={phoneValue}
                        defaultCountry={element.defaultCountry || "BR"}
                        onChange={(val) => element.name && setValue(element.name, val, { shouldValidate: true })}
                        onBlur={() => { /* Handled by useForm mode='onBlur' mostly */ }}
                    />
                );









            case 'toggle':
                const toggleValue = element.name ? watch(element.name) : false;
                return (
                    <Switch
                        key={element.id}
                        {...safeProps}
                        label={element.toggleText || 'Ativar'}
                        name={fieldName}
                        checked={toggleValue || false}
                        onCheckedChange={(checked) => element.name && setValue(element.name, checked)}
                    />
                );

            case 'hidden':
                return (
                    <input
                        key={element.id}
                        type="hidden"
                        value={(element.defaultValue as any) || ''}
                        {...(element.name ? register(element.name) : {})}
                    />
                );




            case 'button':
            case 'submit-button':
            case 'reset-button':
            case 'primary-button':
            case 'secondary-button':
            case 'danger-button': {
                let variantClass = "bg-primary text-white hover:bg-primary/90";
                if (element.type === 'reset-button' || element.type === 'secondary-button') variantClass = "bg-slate-100 text-slate-700 hover:bg-slate-200";
                if (element.type === 'danger-button') variantClass = "bg-red-500 text-white hover:bg-red-600";

                // If in WELCOME state, any button should probably start the form
                const handleClick = (e: React.MouseEvent) => {
                    if (currentFormState === FormState.WELCOME) {
                        e.preventDefault();
                        handleStartForm();
                        return;
                    }

                    if (element.type === 'reset-button') {
                        reset();
                    }
                };

                return (
                    <button
                        key={element.id}
                        type={element.type === 'submit-button' && currentFormState === FormState.FORM ? 'submit' : 'button'}
                        onClick={handleClick}
                        className={`w-full px-4 py-2 rounded-md text-sm font-medium transition-colors shadow-sm ${variantClass}`}
                    >
                        {element.label || 'Button'}
                    </button>
                );
            }


            case 'banner': {
                const heightMap = { sm: '200px', md: '400px', lg: '600px', xl: '800px', custom: element.bannerCustomHeight || '400px' };
                const bannerHeight = heightMap[element.bannerHeight as keyof typeof heightMap] || '400px';

                const getVideoEmbedUrl = (url: string) => {
                    if (!url) return null;
                    const youtubeMatch = url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([^&\s]+)/);
                    if (youtubeMatch) return `https://www.youtube.com/embed/${youtubeMatch[1]}?autoplay=1&mute=1&loop=1&playlist=${youtubeMatch[1]}&controls=0`;
                    const vimeoMatch = url.match(/vimeo\.com\/(\d+)/);
                    if (vimeoMatch) return `https://player.vimeo.com/video/${vimeoMatch[1]}?autoplay=1&muted=1&loop=1&background=1`;
                    return null;
                };

                const videoEmbedUrl = element.backgroundType === 'video' ? getVideoEmbedUrl(element.videoUrl || '') : null;

                return (
                    <div key={element.id} className="w-full relative overflow-hidden rounded-lg mb-6 shadow-sm group" style={{ height: bannerHeight, gridColumn: 'span 12' }}>
                        {/* Background Layer */}
                        {element.backgroundType === 'image' && element.src && (
                            <div
                                className="absolute inset-0 bg-cover bg-center"
                                style={{ backgroundImage: `url(${element.src})` }}
                            />
                        )}

                        {element.backgroundType === 'video' && videoEmbedUrl && (
                            <iframe
                                src={videoEmbedUrl}
                                className="absolute inset-0 w-full h-full pointer-events-none"
                                style={{ transform: 'scale(1.5)' }}
                                allow="autoplay; fullscreen"
                                frameBorder="0"
                            />
                        )}

                        {element.backgroundType === 'color' && (
                            <div
                                className="absolute inset-0"
                                style={{ backgroundColor: element.overlayColor || '#f1f5f9' }}
                            />
                        )}

                        {/* Overlay */}
                        {(element.backgroundType === 'image' || element.backgroundType === 'video') && (
                            <div
                                className="absolute inset-0"
                                style={{
                                    backgroundColor: element.overlayColor || '#000000',
                                    opacity: element.overlayOpacity || 0.3
                                }}
                            />
                        )}

                        {/* Content */}
                        <div className="relative z-10 h-full flex items-center justify-center p-8">
                            <div className="text-center text-white max-w-3xl w-full">
                                {element.children && element.children.length > 0 ? (
                                    <div className="space-y-4 text-white [&_*]:text-white">
                                        {element.children.map(child => renderRecursiveElement(child, undefined, prefixForName))}
                                    </div>
                                ) : null}
                            </div>
                        </div>
                    </div>
                );
            }

            default:
                return (
                    <div key={element.id} className="text-xs text-slate-400 italic">
                        Campo "{element.type}" não suportado ainda
                    </div>
                );
        }
    };

    const hasSteps = safeElements.some(el => el.type === 'steps');

    // Handle form submission with state transition
    const handleFormSubmit = async (data: any) => {
        setIsFormSubmitted(true);

        // Call the original onSubmit handler
        await onSubmit(data);

        // Transition to Thank You page if enabled
        if (thankYouPage?.enabled) {
            setCurrentFormState(FormState.THANK_YOU);
        }
    };

    // Handler to start form from welcome page
    const handleStartForm = () => {
        setCurrentFormState(FormState.FORM);
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    return (
        <ThemeProvider themeConfig={themeConfig}>
            <AnimatePresence mode="wait">
                {/* Welcome State */}
                {currentFormState === FormState.WELCOME && welcomePage && (
                    <WelcomeScreen
                        key="welcome"
                        config={welcomePage}
                        onStart={handleStartForm}
                        themeConfig={themeConfig}
                        renderElement={(el) => renderRecursiveElement(el)}
                    />
                )}

                {/* Form State */}
                {currentFormState === FormState.FORM && (
                    <FormProvider {...methods}>
                        <div key="form-container" className="flex justify-center items-start pt-8 pb-12 px-4 sm:px-6 min-h-screen">
                            <motion.div
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, y: -20 }}
                                transition={{ duration: 0.4 }}
                                className={`bg-white rounded-xl shadow-2xl border border-slate-100 overflow-hidden w-full ${viewDevice ? DEVICE_WIDTHS[viewDevice] : DEVICE_WIDTHS.desktop}`}
                            >
                                <form onSubmit={handleSubmit(handleFormSubmit)} className="p-6 sm:p-10 space-y-6">
                                    <div className="grid grid-cols-12 gap-x-4 sm:gap-x-6 gap-y-6 sm:gap-y-8">
                                        {safeElements.map(el => renderRecursiveElement(el))}
                                    </div>

                                    {(!hasSubmitButton && !hasSteps) && (
                                        <div className="flex justify-end pt-6 border-t border-slate-100 mt-8">
                                            <button
                                                type="submit"
                                                disabled={isSubmitting}
                                                className="px-8 py-3 bg-primary text-primary-foreground rounded-lg hover:opacity-90 disabled:opacity-50 disabled:cursor-not-allowed font-semibold text-sm shadow-md transition-all active:scale-[0.98]"
                                            >
                                                {isSubmitting ? 'Enviando...' : (config?.submitLabel || 'Enviar')}
                                            </button>
                                        </div>
                                    )}
                                </form>
                            </motion.div>
                        </div>
                    </FormProvider>
                )}


                {/* Thank You State */}
                {currentFormState === FormState.THANK_YOU && thankYouPage && (
                    <ThankYouScreen
                        key="thankyou"
                        config={thankYouPage}
                        themeConfig={themeConfig}
                        renderElement={(el) => renderRecursiveElement(el)}
                    />
                )}
            </AnimatePresence>
        </ThemeProvider>
    );
};
