import React from 'react';

interface MatrixProps {
    label?: string;
    error?: string;
    description?: string;
    name: string;
    rows?: Array<{ text: string; value: string }>;
    columns?: Array<{ text: string; value: string }>;
    value?: any;
    // Value shape dependency:
    // variant='radio' -> Record<rowValue, colValue> (string mapping)
    // variant='text'  -> Record<rowValue, Record<colValue, string>> (nested object)

    onValueChange?: (value: any) => void;
    required?: boolean;
    variant?: 'radio' | 'text'; // 'text' for matrix-table
}

const MatrixTextInput = ({ value, onChange }: { value: string, onChange: (val: string) => void }) => {
    const [isFocused, setIsFocused] = React.useState(false);
    return (
        <input
            type="text"
            className={`w-full h-8 text-sm px-2 rounded border transition-all focus:outline-none ${isFocused ? 'border-primary ring-1 ring-primary' : 'border-slate-300'}`}
            value={value}
            onChange={(e) => onChange(e.target.value)}
            onFocus={() => setIsFocused(true)}
            onBlur={() => setIsFocused(false)}
        />
    );
};

export const Matrix: React.FC<MatrixProps> = ({
    label,
    error,
    description,
    name,
    rows = [],
    columns = [],
    value = {},
    onValueChange,
    required,
    variant = 'radio'
}) => {

    const handleRadioChange = (rowVal: string, colVal: string) => {
        const newValue = { ...value, [rowVal]: colVal };
        onValueChange?.(newValue);
    };

    const handleTextChange = (rowVal: string, colVal: string, text: string) => {
        // Nested structure: { [rowId]: { [colId]: text } }
        const rowData = value[rowVal] || {};
        const newValue = {
            ...value,
            [rowVal]: {
                ...rowData,
                [colVal]: text
            }
        };
        onValueChange?.(newValue);
    };

    return (
        <div className="w-full overflow-x-auto">
            {label && (
                <label className="text-sm font-medium mb-3 block text-slate-700">
                    {label}
                    {required && <span className="text-red-500 ml-1">*</span>}
                </label>
            )}

            <table className="w-full text-sm text-left text-slate-600 border-collapse min-w-[300px]">
                <thead>
                    <tr>
                        <th className="p-2 border border-slate-200 bg-slate-50"></th>
                        {columns.map((col) => (
                            <th key={col.value} className="p-2 text-center font-medium border border-slate-200 bg-slate-50 text-xs uppercase tracking-wider">
                                {col.text}
                            </th>
                        ))}
                    </tr>
                </thead>
                <tbody>
                    {rows.map((row, rowIndex) => (
                        <tr key={row.value} className={rowIndex % 2 === 0 ? 'bg-slate-50/30' : 'bg-white'}>
                            <td className="p-3 font-medium border border-slate-200 min-w-[120px]">
                                {row.text}
                            </td>
                            {columns.map((col) => {
                                const rowVal = row.value;
                                const colVal = col.value;

                                return (
                                    <td key={`${rowVal}-${colVal}`} className="p-2 text-center border border-slate-200">
                                        {variant === 'radio' ? (
                                            <div className="flex justify-center">
                                                <input
                                                    type="radio"
                                                    name={`${name}-${rowVal}`}
                                                    value={colVal}
                                                    checked={value?.[rowVal] === colVal}
                                                    onChange={() => handleRadioChange(rowVal, colVal)}
                                                    className="h-4 w-4 border-slate-300 text-primary accent-primary focus:ring-primary cursor-pointer"
                                                />
                                            </div>
                                        ) : (
                                            <MatrixTextInput
                                                value={value?.[rowVal]?.[colVal] || ''}
                                                onChange={(val) => handleTextChange(rowVal, colVal, val)}
                                            />
                                        )}
                                    </td>
                                );
                            })}
                        </tr>
                    ))}
                </tbody>
            </table>

            {description && !error && (
                <p className="text-xs text-slate-500 mt-2">{description}</p>
            )}
            {error && (
                <p className="text-xs text-red-500 mt-2">{error}</p>
            )}
        </div>
    );
};
