import React from 'react';
import { FormElement } from '../../types';
import { BaseProperties } from '../common/BaseProperties';
import { AccordionItem } from '../../../ui/wireframe-ports/Accordion';
import { Input } from '../../../ui/wireframe-ports/Input';
import { Switch } from '../../../ui/fields/Switch';

interface DateTimePropertiesProps {
    element: FormElement;
    onChange: (key: keyof FormElement, value: any) => void;
}

export const DateTimeProperties: React.FC<DateTimePropertiesProps> = ({ element, onChange }) => {
    return (
        <div className="px-5">
            <BaseProperties element={element} onChange={onChange} />

            {element.type === 'time' ? (
                <AccordionItem title="Time options" defaultOpen>
                    <div className="space-y-4 pt-2">
                        <div className="flex items-center justify-between">
                            <label className="text-xs text-slate-700">24-hour format</label>
                            <Switch
                                checked={element.timeFormat24 || false}
                                onCheckedChange={(c) => onChange('timeFormat24', c)}
                            />
                        </div>
                        <div className="flex items-center justify-between">
                            <label className="text-xs text-slate-700">Show seconds</label>
                            <Switch
                                checked={element.timeSeconds || false}
                                onCheckedChange={(c) => onChange('timeSeconds', c)}
                            />
                        </div>
                    </div>
                </AccordionItem>
            ) : (
                <AccordionItem title="Date options" defaultOpen>
                    <div className="space-y-4 pt-2">
                        <Input
                            label="Date format (Display)"
                            value={element.dateFormatDisplay || ''}
                            placeholder="dd/MM/yyyy"
                            onChange={(e) => onChange('dateFormatDisplay', e.target.value)}
                        />
                        <Input
                            label="Min date"
                            value={element.minDate || ''}
                            placeholder="Y-m-d"
                            onChange={(e) => onChange('minDate', e.target.value)}
                        />
                        <Input
                            label="Max date"
                            value={element.maxDate || ''}
                            placeholder="Y-m-d"
                            onChange={(e) => onChange('maxDate', e.target.value)}
                        />
                    </div>
                </AccordionItem>
            )}
        </div>
    );
};
