import React from 'react';
import { FormElement } from '../../types';

interface SlidersCanvasProps {
    element: FormElement;
    isSelected: boolean;
}

export const SlidersCanvas: React.FC<SlidersCanvasProps> = ({ element, isSelected }) => {
    const isVertical = element.type === 'vertical-slider';

    return (
        <div className={`w-full flex items-center justify-center p-4 bg-slate-50/50 rounded-lg border border-slate-100 ${isVertical ? 'h-40' : 'h-16'}`}>
            <div className={`relative ${isVertical ? 'h-full w-2' : 'w-full h-2'} bg-slate-200 rounded-full`}>
                <div
                    className={`absolute bg-primary rounded-full ${isVertical ? 'bottom-0 left-0 right-0 h-1/2' : 'left-0 top-0 bottom-0 w-1/2'}`}
                />
                <div
                    className={`absolute bg-white border-2 border-primary rounded-full shadow-md ${isVertical ? 'left-1/2 -ml-3 bottom-1/2 -mb-3 h-6 w-6' : 'top-1/2 -mt-3 left-1/2 -ml-3 h-6 w-6'}`}
                />
            </div>
        </div>
    );
};
