import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';

interface RangeSliderProps {
    label?: string;
    error?: string;
    description?: string;
    min?: number;
    max?: number;
    step?: number;
    value?: number[];
    onValueChange?: (value: number[]) => void;
    required?: boolean;
    disabled?: boolean;
    name: string;
    showSteps?: boolean;
    sliderFormatPrefix?: string;
    sliderFormatSuffix?: string;
}

export const RangeSlider: React.FC<RangeSliderProps> = ({
    label,
    error,
    description,
    min = 0,
    max = 100,
    step = 1,
    value,
    onValueChange,
    required,
    disabled,
    name,
    showSteps = true,
    sliderFormatPrefix = '',
    sliderFormatSuffix = ''
}) => {
    // Standardize value to array
    const getInitialValue = () => {
        if (Array.isArray(value)) return [...value];
        if (typeof value === 'number') return [value];
        return [min, max];
    };

    const [localValue, setLocalValue] = useState<number[]>(getInitialValue());
    const sliderRef = useRef<HTMLDivElement>(null);
    const activeIndexRef = useRef<number | null>(null);
    const valueRef = useRef<number[]>(localValue);

    // Sync ref with state
    useEffect(() => {
        valueRef.current = localValue;
    }, [localValue]);

    // Sync state with prop
    useEffect(() => {
        const newValue = getInitialValue();
        // Only update if actually different to avoid infinite loops
        if (JSON.stringify(newValue) !== JSON.stringify(localValue)) {
            setLocalValue(newValue);
        }
    }, [value, min, max]);

    const getPercentage = useCallback((val: number) => {
        const range = max - min;
        if (range === 0) return 0;
        const pct = ((val - min) / range) * 100;
        return Math.min(Math.max(pct, 0), 100);
    }, [min, max]);

    const handleMove = useCallback((clientX: number) => {
        if (!sliderRef.current || activeIndexRef.current === null) return;

        const rect = sliderRef.current.getBoundingClientRect();
        const percentage = Math.min(Math.max((clientX - rect.left) / rect.width, 0), 1);
        let newValue = min + percentage * (max - min);

        // Snap to step
        newValue = Math.round(newValue / step) * step;
        newValue = Math.min(Math.max(newValue, min), max);

        const nextValues = [...valueRef.current];
        nextValues[activeIndexRef.current] = newValue;
        setLocalValue(nextValues);
    }, [min, max, step]);

    const onMouseMove = useCallback((e: MouseEvent) => {
        handleMove(e.clientX);
    }, [handleMove]);

    const onTouchMove = useCallback((e: TouchEvent) => {
        if (e.touches[0]) {
            handleMove(e.touches[0].clientX);
        }
    }, [handleMove]);

    const onEnd = useCallback(() => {
        if (activeIndexRef.current !== null) {
            // Sort values on finish to maintain logical range
            const sorted = [...valueRef.current].sort((a, b) => a - b);
            onValueChange?.(sorted);
            setLocalValue(sorted);
        }
        activeIndexRef.current = null;
        document.removeEventListener('mousemove', onMouseMove);
        document.removeEventListener('mouseup', onEnd);
        document.removeEventListener('touchmove', onTouchMove);
        document.removeEventListener('touchend', onEnd);
    }, [onValueChange, onMouseMove, onTouchMove]);

    const onStart = (e: React.MouseEvent | React.TouchEvent, index: number) => {
        if (disabled) return;
        e.preventDefault();
        activeIndexRef.current = index;

        document.addEventListener('mousemove', onMouseMove);
        document.addEventListener('mouseup', onEnd);
        document.addEventListener('touchmove', onTouchMove, { passive: false });
        document.addEventListener('touchend', onEnd);
    };

    // Cleanup on unmount
    useEffect(() => {
        return () => {
            document.removeEventListener('mousemove', onMouseMove);
            document.removeEventListener('mouseup', onEnd);
            document.removeEventListener('touchmove', onTouchMove);
            document.removeEventListener('touchend', onEnd);
        };
    }, [onMouseMove, onTouchMove, onEnd]);

    const minVal = Math.min(...localValue);
    const maxVal = Math.max(...localValue);

    const stepMarks = useMemo(() => {
        if (!showSteps || step <= 0 || (max - min) / step > 100) return [];
        const marks = [];
        for (let i = min; i <= max; i += step) {
            marks.push(i);
        }
        return marks;
    }, [min, max, step, showSteps]);

    const formatValue = (val: number) => {
        return `${sliderFormatPrefix}${val}${sliderFormatSuffix}`;
    };

    return (
        <div className="w-full pt-10 pb-4 group">
            <div className="relative h-6 flex items-center select-none touch-none" ref={sliderRef}>
                {/* Track Background */}
                <div className="absolute w-full h-1.5 bg-slate-200 rounded-full"></div>

                {/* Step Ticks */}
                {stepMarks.map((mark) => (
                    <div
                        key={mark}
                        className="absolute w-0.5 h-2.5 bg-slate-300 transform -translate-x-1/2"
                        style={{ left: `${getPercentage(mark)}%` }}
                    />
                ))}

                {/* Range Highlight */}
                {localValue.length > 1 && (
                    <div
                        className="absolute h-1.5 bg-primary rounded-full transition-all duration-75"
                        style={{
                            left: `${getPercentage(minVal)}%`,
                            width: `${getPercentage(maxVal) - getPercentage(minVal)}%`
                        }}
                    ></div>
                )}
                {localValue.length === 1 && (
                    <div
                        className="absolute h-1.5 bg-primary rounded-full transition-all duration-75"
                        style={{
                            left: '0%',
                            width: `${getPercentage(localValue[0])}%`
                        }}
                    ></div>
                )}

                {/* Thumbs */}
                {localValue.map((val, idx) => (
                    <div
                        key={idx}
                        className={`
                            absolute w-4.5 h-4.5 bg-primary border-2 border-white rounded-full cursor-grab active:cursor-grabbing shadow-md flex items-center justify-center transform -translate-x-1/2 z-20 hover:scale-110 active:scale-125 transition-transform
                            ${disabled ? 'opacity-50 cursor-not-allowed' : ''}
                        `}
                        style={{ left: `${getPercentage(val)}%` }}
                        onMouseDown={(e) => onStart(e, idx)}
                        onTouchStart={(e) => onStart(e, idx)}
                    >
                        {/* Tooltip */}
                        <div className="absolute -top-9 left-1/2 -translate-x-1/2">
                            <div className="relative bg-primary text-primary-foreground text-[10px] font-bold px-1.5 py-0.5 rounded shadow-lg whitespace-nowrap min-w-[1.4rem] text-center">
                                {formatValue(val)}
                                <div className="absolute top-full left-1/2 -translate-x-1/2 border-[3px] border-transparent border-t-primary"></div>
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            <div className="flex justify-between mt-3 text-[10px] text-slate-400 font-medium">
                <span>{formatValue(min)}</span>
                <span>{formatValue(max)}</span>
            </div>

            {(description || error) && (
                <div className="mt-2 text-xs">
                    {description && !error && <p className="text-slate-500">{description}</p>}
                    {error && <p className="text-red-500 font-medium">{error}</p>}
                </div>
            )}
        </div>
    );
};
