import React from 'react';
import { FormElement } from '../../types';

interface TextAreaCanvasProps {
    element: FormElement;
    isSelected: boolean;
}

export const TextAreaCanvas: React.FC<TextAreaCanvasProps> = ({ element, isSelected }) => {
    return (
        <textarea
            disabled={element.disabled}
            readOnly={element.readOnly}
            placeholder={element.placeholder}
            defaultValue={element.defaultValue as any}
            rows={element.rows || 3}
            className={`w-full rounded-md border bg-white px-3 py-2 text-sm resize-none ${isSelected ? 'border-primary' : 'border-slate-300'} ${element.disabled ? 'bg-slate-100 text-slate-400 cursor-not-allowed' : ''}`}
        />
    );
};
