import React from 'react';
import { FormElement } from '../../types';
import { BaseProperties } from '../common/BaseProperties';
import { Input } from '../../../ui/wireframe-ports/Input';
import { AccordionItem } from '../../../ui/wireframe-ports/Accordion';

interface AdvancedPropertiesProps {
    element: FormElement;
    onChange: (key: keyof FormElement, value: any) => void;
}

export const AdvancedProperties: React.FC<AdvancedPropertiesProps> = ({ element, onChange }) => {
    return (
        <div className="px-5">
            <BaseProperties element={element} onChange={onChange} />

            {element.type === 'signature' && (
                <AccordionItem title="Signature options" defaultOpen>
                    <div className="space-y-4 pt-2">
                        <Input
                            label="Canvas width"
                            value={element.canvasMaxWidth || 'auto'}
                            onChange={(e) => onChange('canvasMaxWidth', e.target.value)}
                        />
                        <Input
                            label="Canvas height"
                            type="number"
                            value={element.canvasHeight || 160}
                            onChange={(e) => onChange('canvasHeight', parseInt(e.target.value))}
                        />
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-xs text-slate-700 block mb-1">Pen Color</label>
                                <input
                                    type="color"
                                    value={element.penColor || '#000000'}
                                    onChange={(e) => onChange('penColor', e.target.value)}
                                    className="w-full h-8 rounded border border-slate-200 cursor-pointer"
                                />
                            </div>
                            <div>
                                <label className="text-xs text-slate-700 block mb-1">BG Color</label>
                                <input
                                    type="color"
                                    value={element.backgroundColor || '#ffffff'}
                                    onChange={(e) => onChange('backgroundColor', e.target.value)}
                                    className="w-full h-8 rounded border border-slate-200 cursor-pointer"
                                />
                            </div>
                        </div>
                    </div>
                </AccordionItem>
            )}
        </div>
    );
};
