import React from 'react';
import { FormElement } from '../../types';
import { Matrix } from '../../../ui/fields/Matrix';
import { useFormContext } from 'react-hook-form';

interface MatrixRendererProps {
    element: FormElement;
    prefix?: string;
}

export const MatrixRenderer: React.FC<MatrixRendererProps> = ({
    element,
    prefix = ''
}) => {
    const { watch, setValue, formState: { errors } } = useFormContext();
    const fieldName = prefix
        ? `${prefix}${element.name ? `.${element.name}` : ''}`
        : element.name || `element_${element.id.replace(/-/g, '_')}`;

    const error = errors[fieldName]?.message as string | undefined;
    const value = watch(fieldName) || (element.type === 'matrix-table' ? {} : {});

    return (
        <Matrix
            key={element.id}
            name={fieldName}
            label={element.label}
            description={element.description}
            error={error}
            required={element.required}
            rows={element.matrixRows || []}
            columns={element.matrixColumns || []}
            value={value}
            variant={element.type === 'matrix-table' ? 'text' : 'radio'}
            onValueChange={(val) => setValue(fieldName, val, { shouldValidate: true })}
        />
    );
};
