import React from 'react';
import { FormElement } from '../../types';

interface SelectCanvasProps {
    element: FormElement;
    isSelected: boolean;
}

export const SelectCanvas: React.FC<SelectCanvasProps> = ({ element, isSelected }) => {
    if (element.type === 'tags') {
        return (
            <div className={`w-full min-h-9 rounded-md border bg-white px-2 py-1 text-sm flex items-center ${isSelected ? 'border-primary' : 'border-slate-300'} ${element.disabled ? 'bg-slate-100' : ''}`}>
                <div className="flex gap-1 flex-wrap w-full">
                    <span className="bg-primary/10 text-primary border border-primary/20 rounded px-1.5 py-0.5 text-xs flex items-center gap-1">
                        Tag 1 <span className="cursor-pointer">×</span>
                    </span>
                    <input className="outline-none bg-transparent flex-1 min-w-[60px] px-1" placeholder={element.placeholder || "Add tag..."} disabled={element.disabled} />
                </div>
            </div>
        );
    }

    return (
        <div className={`w-full h-9 rounded-md border bg-white px-3 text-sm flex items-center justify-between ${isSelected ? 'border-primary' : 'border-slate-300'} ${element.disabled ? 'bg-slate-100 text-slate-400' : 'text-slate-700'}`}>
            <span className={!element.placeholder ? "text-slate-500" : ""}>{element.placeholder || 'Select...'}</span>
            <svg className="h-4 w-4 opacity-50" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
        </div>
    );
};
