import React from 'react';

interface InputProps extends Omit<React.InputHTMLAttributes<HTMLInputElement>, 'size'> {
    label?: string;
    error?: string;
    description?: string;
    prefix?: string;
    suffix?: string;
    before?: string;
    between?: string;
    after?: string;
    mask?: string;
    size?: 'default' | 'sm' | 'md' | 'lg';
}

import { applyMask } from '@/components/form-engine/core/utils';

export const Input = React.forwardRef<HTMLInputElement, InputProps>(
    ({ className, type, label, prefix, suffix, error, description, before, between, after, mask, onChange, size = 'md', ...props }, ref) => {
        const [isFocused, setIsFocused] = React.useState(false);

        const sizeClasses = {
            sm: 'h-8 text-xs px-2',
            md: 'h-10 text-sm px-3',
            lg: 'h-12 text-base px-4',
            default: 'h-10 text-sm px-3'
        };

        const currentSizeClass = sizeClasses[size as keyof typeof sizeClasses] || sizeClasses.md;

        const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
            if (mask) {
                const masked = applyMask(e.target.value, mask);
                e.target.value = masked;
            }
            if (onChange) {
                onChange(e);
            }
        };

        return (
            <div
                className={`flex items-center w-full rounded-md border bg-muted/30 transition-all ${error ? 'border-red-500' : isFocused ? 'border-primary ring-1 ring-primary/20' : 'border-border/50'} ${props.disabled ? 'bg-muted opacity-50' : ''} ${className || ''}`}
                onFocus={() => setIsFocused(true)}
                onBlur={() => setIsFocused(false)}
            >
                {prefix && (
                    <span
                        className="text-slate-400 mr-2 text-sm shrink-0 select-none flex items-center ml-3"
                        dangerouslySetInnerHTML={{ __html: prefix }}
                    />
                )}
                <input
                    type={type}
                    className={`flex w-full bg-transparent py-1 placeholder:text-muted-foreground/40 focus:outline-none disabled:cursor-not-allowed ${currentSizeClass}`}
                    ref={ref}
                    onChange={handleChange}
                    {...props}
                />
                {suffix && (
                    <span
                        className="text-slate-400 ml-2 text-sm shrink-0 select-none flex items-center mr-3"
                        dangerouslySetInnerHTML={{ __html: suffix }}
                    />
                )}
            </div>
        );
    }
);
Input.displayName = "Input";
