import React, { useRef, useEffect, useState } from 'react';
import { Bold, Italic, Underline as UnderlineIcon, Link as LinkIcon, Heading1, Quote, Code, List, ListOrdered, AlignLeft, AlignCenter, AlignRight, Paperclip, Undo, Redo } from 'lucide-react';

interface RichTextEditorProps {
    label?: string;
    error?: string;
    description?: string;
    value?: string;
    onChange?: (value: string) => void;
    name: string;
    placeholder?: string;
    required?: boolean;
    disabled?: boolean;
}

export const RichTextEditor: React.FC<RichTextEditorProps> = ({
    label,
    error,
    description,
    value,
    onChange,
    name,
    placeholder,
    required,
    disabled
}) => {
    const editorRef = useRef<HTMLDivElement>(null);
    const isInternalChange = useRef(false);
    const [isFocused, setIsFocused] = useState(false);

    // Sync external value changes to editor content
    useEffect(() => {
        // If the change came from the editor itself, don't update innerHTML
        // to avoid cursor jumping.
        if (isInternalChange.current) {
            isInternalChange.current = false;
            return;
        }

        if (editorRef.current) {
            const currentHTML = editorRef.current.innerHTML;
            const normalizedValue = value || '';

            // Only update if content is actually different
            // We also handle the case where browser adds <br> to empty elements
            if (normalizedValue !== currentHTML && normalizedValue !== (currentHTML === '<br>' ? '' : currentHTML)) {
                editorRef.current.innerHTML = normalizedValue;
            }
        }
    }, [value]);

    const exec = (command: string, val: string | undefined = undefined) => {
        if (disabled) return;
        document.execCommand(command, false, val);
        triggerChange();
        editorRef.current?.focus();
    };

    const handleLink = () => {
        const url = prompt('Enter URL:');
        if (url) exec('createLink', url);
    };

    const triggerChange = () => {
        if (editorRef.current && onChange) {
            const html = editorRef.current.innerHTML;
            isInternalChange.current = true;
            onChange(html === '<br>' ? '' : html);
        }
    };

    const ToolbarButton = ({ icon: Icon, command, arg, active = false }: { icon: any, command: string, arg?: string, active?: boolean }) => (
        <button
            type="button"
            onClick={(e) => { e.preventDefault(); command === 'createLink' ? handleLink() : exec(command, arg); }}
            className={`p-1.5 rounded transition-colors ${active ? 'bg-slate-200 text-slate-900' : 'text-slate-500 hover:bg-slate-200'}`}
            disabled={disabled}
            title={command}
        >
            <Icon size={16} />
        </button>
    );

    return (
        <div className="w-full">
            {label && (
                <label className="text-sm font-medium mb-1.5 block text-slate-700">
                    {label}
                    {required && <span className="text-red-500 ml-1">*</span>}
                </label>
            )}

            <div className={`border rounded-md overflow-hidden bg-white shadow-sm transition-all ${error ? 'border-red-500' : isFocused ? 'border-primary ring-1 ring-primary' : 'border-slate-300'}`} onFocus={() => setIsFocused(true)} onBlur={() => setIsFocused(false)}>
                {/* Toolbar */}
                <div className="flex items-center gap-1 bg-slate-50 border-b border-slate-200 p-2 flex-wrap">
                    <ToolbarButton icon={Bold} command="bold" />
                    <ToolbarButton icon={Italic} command="italic" />
                    <ToolbarButton icon={UnderlineIcon} command="underline" />
                    <div className="w-px h-4 bg-slate-300 mx-1" />
                    <ToolbarButton icon={LinkIcon} command="createLink" />
                    <ToolbarButton icon={Heading1} command="formatBlock" arg="H2" />{/* H2 usually safer inside form than H1 */}
                    <ToolbarButton icon={Quote} command="formatBlock" arg="BLOCKQUOTE" />

                    <div className="w-px h-4 bg-slate-300 mx-1" />
                    <ToolbarButton icon={List} command="insertUnorderedList" />
                    <ToolbarButton icon={ListOrdered} command="insertOrderedList" />
                    <div className="w-px h-4 bg-slate-300 mx-1" />
                    <ToolbarButton icon={AlignLeft} command="justifyLeft" />
                    <ToolbarButton icon={AlignCenter} command="justifyCenter" />
                    <ToolbarButton icon={AlignRight} command="justifyRight" />
                    <div className="w-px h-4 bg-slate-300 mx-1" />
                    <ToolbarButton icon={Undo} command="undo" />
                    <ToolbarButton icon={Redo} command="redo" />
                </div>

                {/* Editor Area */}
                <div
                    ref={editorRef}
                    contentEditable={!disabled}
                    onInput={triggerChange}
                    suppressContentEditableWarning={true}
                    className="w-full p-4 min-h-[150px] outline-none text-sm text-slate-700 resize-y overflow-auto prose prose-sm max-w-none prose-p:my-1 prose-headings:my-2 prose-ul:my-1 prose-ol:my-1 [&_ul]:list-disc [&_ul]:pl-5 [&_ol]:list-decimal [&_ol]:pl-5"
                    style={{ minHeight: '150px' }}
                />
            </div>

            {description && !error && <p className="text-xs text-slate-500 mt-1">{description}</p>}
            {error && <p className="text-xs text-red-500 mt-1">{error}</p>}
        </div>
    );
};
